import type { Article, LawSection } from '../../../common/types/law.types';

export const SECTION_17: LawSection = { id: 'ccyc-s17', lawId: 'codigo-civil-comercial', number: 'XVII', name: 'Libro Quinto - Sucesiones II (Arts. 2421-2531)', articleStart: 2421, articleEnd: 2531, titles: [] };

export const ARTICLES_17: Article[] = [
  { id: 'ccyc-art-2421', lawId: 'codigo-civil-comercial', number: '2421', order: 2421, title: "Enajenación de bienes", text: "Enajenación de bienes. La partición hecha por testamento es revocable por el causante y sólo produce efectos después de su muerte. La enajenación posterior al testamento de alguno de los bienes incluidos en la partición no afecta su validez, sin perjuicio de las acciones protectoras de la porción legítima que pueden corresponder. Sus beneficiarios no pueden renunciar a ella para solicitar una nueva partición, excepto por acuerdo unánime.", plainLanguageExplanation: "Establece el régimen de enajenación de bienes. La partición hecha por testamento es revocable por el causante y sólo produce efectos después de su muerte.", practicalEffects: ['En la práctica, este artículo rige enajenación de bienes. La partición hecha por testamento es revocable por el causante y sólo produce efectos después de su muerte.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['enajenacin', 'bienes', 'articulo 2421'], segments: [], amendments: [] },
  { id: 'ccyc-art-2422', lawId: 'codigo-civil-comercial', number: '2422', order: 2422, title: "Efectos", text: "Efectos. La partición por testamento tiene los mismos efectos que la practicada por los herederos.", plainLanguageExplanation: "Establece el régimen de efectos. La partición por testamento tiene los mismos efectos que la practicada por los herederos.", practicalEffects: ['En la práctica, este artículo rige efectos. La partición por testamento tiene los mismos efectos que la practicada por los herederos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 2422'], segments: [], amendments: [] },
  { id: 'ccyc-art-2423', lawId: 'codigo-civil-comercial', number: '2423', order: 2423, title: "Garantía de evicción", text: "Garantía de evicción. Los herederos se deben recíprocamente garantía de evicción de los bienes comprendidos en sus lotes. La existencia y legitimidad de los derechos transmitidos se juzga al tiempo de la muerte del causante. TITULO IX Sucesiones intestadas CAPITULO 1 Disposiciones generales", plainLanguageExplanation: "Establece el régimen de garantía de evicción. Los herederos se deben recíprocamente garantía de evicción de los bienes comprendidos en sus lotes.", practicalEffects: ['En la práctica, este artículo rige garantía de evicción. Los herederos se deben recíprocamente garantía de evicción de los bienes comprendidos en sus lotes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['garanta', 'eviccin', 'articulo 2423'], segments: [], amendments: [] },
  { id: 'ccyc-art-2424', lawId: 'codigo-civil-comercial', number: '2424', order: 2424, title: "Heredero legítimo", text: "Heredero legítimo. Las sucesiones intestadas se defieren a los descendientes del causante, a sus ascendientes, al cónyuge supérstite, y a los parientes colaterales dentro del cuarto grado inclusive, en el orden y según las reglas establecidas en este Código. A falta de herederos, los bienes corresponden al Estado nacional, provincial o a la Ciudad Autónoma de Buenos Aires, según el lugar en que están situados.", plainLanguageExplanation: "Establece el régimen de heredero legítimo. Las sucesiones intestadas se defieren a los descendientes del causante, a sus ascendientes, al cónyuge supérstite, y a los parientes colaterales dentro del cuarto grado inclusive, en el orden y según las reglas establecidas en este Código.", practicalEffects: ['En la práctica, este artículo rige heredero legítimo. Las sucesiones intestadas se defieren a los descendientes del causante, a sus ascendientes, al cónyuge supérstite, y a los parientes colaterales dentr'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['heredero', 'legtimo', 'articulo 2424'], segments: [], amendments: [] },
  { id: 'ccyc-art-2425', lawId: 'codigo-civil-comercial', number: '2425', order: 2425, title: "Naturaleza y origen de los bienes", text: "Naturaleza y origen de los bienes. En las sucesiones intestadas no se atiende a la naturaleza ni al origen de los bienes que componen la herencia, excepto disposición legal expresa en contrario. CAPITULO 2 Sucesión de los descendientes", plainLanguageExplanation: "Establece el régimen de naturaleza y origen de los bienes. En las sucesiones intestadas no se atiende a la naturaleza ni al origen de los bienes que componen la herencia, excepto disposición legal expresa en contrario.", practicalEffects: ['En la práctica, este artículo rige naturaleza y origen de los bienes. En las sucesiones intestadas no se atiende a la naturaleza ni al origen de los bienes que componen la herencia, excepto disposición legal expresa en contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['naturaleza', 'origen', 'bienes', 'articulo 2425'], segments: [], amendments: [] },
  { id: 'ccyc-art-2426', lawId: 'codigo-civil-comercial', number: '2426', order: 2426, title: "Sucesión de los hijos", text: "Sucesión de los hijos. Los hijos del causante lo heredan por derecho propio y por partes iguales.", plainLanguageExplanation: "Establece el régimen de sucesión de los hijos. Los hijos del causante lo heredan por derecho propio y por partes iguales.", practicalEffects: ['En la práctica, este artículo rige sucesión de los hijos. Los hijos del causante lo heredan por derecho propio y por partes iguales.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sucesin', 'hijos', 'articulo 2426'], segments: [], amendments: [] },
  { id: 'ccyc-art-2427', lawId: 'codigo-civil-comercial', number: '2427', order: 2427, title: "Sucesión de los demás descendientes", text: "Sucesión de los demás descendientes. Los demás descendientes heredan por derecho de representación, sin limitación de grados.", plainLanguageExplanation: "Establece el régimen de sucesión de los demás descendientes. Los demás descendientes heredan por derecho de representación, sin limitación de grados.", practicalEffects: ['En la práctica, este artículo rige sucesión de los demás descendientes. Los demás descendientes heredan por derecho de representación, sin limitación de grados.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sucesin', 'dems', 'descendientes', 'articulo 2427'], segments: [], amendments: [] },
  { id: 'ccyc-art-2428', lawId: 'codigo-civil-comercial', number: '2428', order: 2428, title: "Efectos de la representación", text: "Efectos de la representación. En caso de concurrir descendientes por representación, la sucesión se divide por estirpes, como si el representado concurriera. Si la representación desciende más de un grado, la subdivisión vuelve a hacerse por estirpe en cada rama. Dentro de cada rama o subdivisión de rama, la división se hace por cabeza.", plainLanguageExplanation: "Establece el régimen de efectos de la representación. En caso de concurrir descendientes por representación, la sucesión se divide por estirpes, como si el representado concurriera.", practicalEffects: ['En la práctica, este artículo rige efectos de la representación. En caso de concurrir descendientes por representación, la sucesión se divide por estirpes, como si el representado concurriera.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectos', 'representacin', 'articulo 2428'], segments: [], amendments: [] },
  { id: 'ccyc-art-2429', lawId: 'codigo-civil-comercial', number: '2429', order: 2429, title: "Casos en que tiene lugar", text: "Casos en que tiene lugar. La representación tiene lugar en caso de premoriencia, renuncia o indignidad del ascendiente. No la impide la renuncia a la herencia del ascendiente, pero sí la indignidad en la sucesión de éste. Se aplica también en la sucesión testamentaria, si el testador se limita a confirmar la distribución a la herencia que resulta de la ley.", plainLanguageExplanation: "Establece el régimen de casos en que tiene lugar. La representación tiene lugar en caso de premoriencia, renuncia o indignidad del ascendiente.", practicalEffects: ['En la práctica, este artículo rige casos en que tiene lugar. La representación tiene lugar en caso de premoriencia, renuncia o indignidad del ascendiente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['casos', 'tiene', 'lugar', 'articulo 2429'], segments: [], amendments: [] },
  { id: 'ccyc-art-2430', lawId: 'codigo-civil-comercial', number: '2430', order: 2430, title: "Caso de adopción", text: "Caso de adopción. El adoptado y sus descendientes tienen los mismos derechos hereditarios que el hijo y sus descendientes por naturaleza y mediante técnicas de reproducción humana asistida. CAPITULO 3 Sucesión de los ascendientes", plainLanguageExplanation: "Establece el régimen de caso de adopción. El adoptado y sus descendientes tienen los mismos derechos hereditarios que el hijo y sus descendientes por naturaleza y mediante técnicas de reproducción humana asistida.", practicalEffects: ['En la práctica, este artículo rige caso de adopción. El adoptado y sus descendientes tienen los mismos derechos hereditarios que el hijo y sus descendientes por naturaleza y mediante técnicas de reproducción humana asistida.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caso', 'adopcin', 'articulo 2430'], segments: [], amendments: [] },
  { id: 'ccyc-art-2431', lawId: 'codigo-civil-comercial', number: '2431', order: 2431, title: "Supuestos de procedencia", text: "Supuestos de procedencia. División. A falta de descendientes, heredan los ascendientes más próximos en grado, quienes dividen la herencia por partes iguales.", plainLanguageExplanation: "Establece el régimen de supuestos de procedencia. División.", practicalEffects: ['En la práctica, este artículo rige supuestos de procedencia. División.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['supuestos', 'procedencia', 'articulo 2431'], segments: [], amendments: [] },
  { id: 'ccyc-art-2432', lawId: 'codigo-civil-comercial', number: '2432', order: 2432, title: "Parentesco por adopción", text: "Parentesco por adopción. Los adoptantes son considerados ascendientes. Sin embargo, en la adopción simple, ni los adoptantes heredan los bienes que el adoptado haya recibido a título gratuito de su familia de origen, ni ésta hereda los bienes que el adoptado haya recibido a título gratuito de su familia de adopción. Estas exclusiones no operan si, en su consecuencia, quedan bienes vacantes. En los demás bienes, los adoptantes excluyen a los padres de origen. CAPITULO 4 Sucesión del cónyuge", plainLanguageExplanation: "Establece el régimen de parentesco por adopción. Los adoptantes son considerados ascendientes.", practicalEffects: ['En la práctica, este artículo rige parentesco por adopción. Los adoptantes son considerados ascendientes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['parentesco', 'adopcin', 'articulo 2432'], segments: [], amendments: [] },
  { id: 'ccyc-art-2433', lawId: 'codigo-civil-comercial', number: '2433', order: 2433, title: "Concurrencia con descendientes", text: "Concurrencia con descendientes. Si heredan los descendientes, el cónyuge tiene en el acervo hereditario la misma parte que un hijo. En todos los casos en que el viudo o viuda es llamado en concurrencia con descendientes, el cónyuge supérstite no tiene parte alguna en la división de bienes gananciales que corresponden al cónyuge prefallecido.", plainLanguageExplanation: "Establece el régimen de concurrencia con descendientes. Si heredan los descendientes, el cónyuge tiene en el acervo hereditario la misma parte que un hijo.", practicalEffects: ['En la práctica, este artículo rige concurrencia con descendientes. Si heredan los descendientes, el cónyuge tiene en el acervo hereditario la misma parte que un hijo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['concurrencia', 'descendientes', 'articulo 2433'], segments: [], amendments: [] },
  { id: 'ccyc-art-2434', lawId: 'codigo-civil-comercial', number: '2434', order: 2434, title: "Concurrencia con ascendientes", text: "Concurrencia con ascendientes. Si heredan los ascendientes, al cónyuge le corresponde la mitad de la herencia.", plainLanguageExplanation: "Establece el régimen de concurrencia con ascendientes. Si heredan los ascendientes, al cónyuge le corresponde la mitad de la herencia.", practicalEffects: ['En la práctica, este artículo rige concurrencia con ascendientes. Si heredan los ascendientes, al cónyuge le corresponde la mitad de la herencia.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['concurrencia', 'ascendientes', 'articulo 2434'], segments: [], amendments: [] },
  { id: 'ccyc-art-2435', lawId: 'codigo-civil-comercial', number: '2435', order: 2435, title: "Exclusión de colaterales", text: "Exclusión de colaterales. A falta de descendientes y ascendientes, el cónyuge hereda la totalidad, con exclusión de los colaterales.", plainLanguageExplanation: "Establece el régimen de exclusión de colaterales. A falta de descendientes y ascendientes, el cónyuge hereda la totalidad, con exclusión de los colaterales.", practicalEffects: ['En la práctica, este artículo rige exclusión de colaterales. A falta de descendientes y ascendientes, el cónyuge hereda la totalidad, con exclusión de los colaterales.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['exclusin', 'colaterales', 'articulo 2435'], segments: [], amendments: [] },
  { id: 'ccyc-art-2436', lawId: 'codigo-civil-comercial', number: '2436', order: 2436, title: "Matrimonio 'in extremis'", text: "Matrimonio 'in extremis'. La sucesión del cónyuge no tiene lugar si el causante muere dentro de los treinta días de contraído el matrimonio a consecuencia de enfermedad existente en el momento de la celebración, conocida por el supérstite, y de desenlace fatal previsible, excepto que el matrimonio sea precedido de una unión convivencial.", plainLanguageExplanation: "Establece el régimen de matrimonio 'in extremis'. La sucesión del cónyuge no tiene lugar si el causante muere dentro de los treinta días de contraído el matrimonio a consecuencia de enfermedad existente en el momento de la celebración, conocida por el supérstite, y de desenlace fatal previsible, excepto que el matrimonio sea pre", practicalEffects: ['En la práctica, este artículo rige matrimonio \'in extremis\'. La sucesión del cónyuge no tiene lugar si el causante muere dentro de los treinta días de contraído el matrimonio a consecuencia de enfermedad existen'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['matrimonio', 'extremis', 'articulo 2436'], segments: [], amendments: [] },
  { id: 'ccyc-art-2437', lawId: 'codigo-civil-comercial', number: '2437', order: 2437, title: "Divorcio, separación de hecho y cese de la convivencia resultante de una decisión judicial", text: "Divorcio, separación de hecho y cese de la convivencia resultante de una decisión judicial. El divorcio, la separación de hecho sin voluntad de unirse y la decisión judicial de cualquier tipo que implica cese de la convivencia, excluyen el derecho hereditario entre cónyuges. CAPITULO 5 Sucesión de los colaterales", plainLanguageExplanation: "Establece el régimen de divorcio, separación de hecho y cese de la convivencia resultante de una decisión judicial. El divorcio, la separación de hecho sin voluntad de unirse y la decisión judicial de cualquier tipo que implica cese de la convivencia, excluyen el derecho hereditario entre cónyuges.", practicalEffects: ['En la práctica, este artículo rige divorcio, separación de hecho y cese de la convivencia resultante de una decisión judicial. El divorcio, la separación de hecho sin voluntad de unirse y la decisión judicial de cualquier tipo que implica cese de la convivencia, excluyen el derecho hereditario entre cónyuges.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['divorcio', 'separacin', 'hecho', 'cese', 'convivencia', 'resultante', 'decisin', 'judicial', 'articulo 2437'], segments: [], amendments: [] },
  { id: 'ccyc-art-2438', lawId: 'codigo-civil-comercial', number: '2438', order: 2438, title: "Extensión", text: "Extensión. A falta de descendientes, ascendientes y cónyuge, heredan los parientes colaterales hasta el cuarto grado inclusive.", plainLanguageExplanation: "Establece el régimen de extensión. A falta de descendientes, ascendientes y cónyuge, heredan los parientes colaterales hasta el cuarto grado inclusive.", practicalEffects: ['En la práctica, este artículo rige extensión. A falta de descendientes, ascendientes y cónyuge, heredan los parientes colaterales hasta el cuarto grado inclusive.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extensinarticulo 2438'], segments: [], amendments: [] },
  { id: 'ccyc-art-2439', lawId: 'codigo-civil-comercial', number: '2439', order: 2439, title: "Orden", text: "Orden. Los colaterales de grado más próximo excluyen a los de grado ulterior, excepto el derecho de representación de los descendientes de los hermanos, hasta el cuarto grado en relación al causante. Los hermanos y descendientes de hermanos desplazan a los demás colaterales.", plainLanguageExplanation: "Establece el régimen de orden. Los colaterales de grado más próximo excluyen a los de grado ulterior, excepto el derecho de representación de los descendientes de los hermanos, hasta el cuarto grado en relación al causante.", practicalEffects: ['En la práctica, este artículo rige orden. Los colaterales de grado más próximo excluyen a los de grado ulterior, excepto el derecho de representación de los descendientes de los hermanos, hasta el cuarto grado en relación al causante.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ordenarticulo 2439'], segments: [], amendments: [] },
  { id: 'ccyc-art-2440', lawId: 'codigo-civil-comercial', number: '2440', order: 2440, title: "División", text: "División. En la concurrencia entre hermanos bilaterales y hermanos unilaterales, cada uno de éstos hereda la mitad de lo que hereda cada uno de aquéllos. En los demás casos, los colaterales que concurren heredan por partes iguales. CAPITULO 6 Derechos del Estado", plainLanguageExplanation: "Establece el régimen de división. En la concurrencia entre hermanos bilaterales y hermanos unilaterales, cada uno de éstos hereda la mitad de lo que hereda cada uno de aquéllos.", practicalEffects: ['En la práctica, este artículo rige división. En la concurrencia entre hermanos bilaterales y hermanos unilaterales, cada uno de éstos hereda la mitad de lo que hereda cada uno de aquéllos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['divisinarticulo 2440'], segments: [], amendments: [] },
  { id: 'ccyc-art-2441', lawId: 'codigo-civil-comercial', number: '2441', order: 2441, title: "Declaración de vacancia", text: "Declaración de vacancia. A pedido de cualquier interesado o del Ministerio Público, se debe declarar vacante la herencia si no hay herederos aceptantes ni el causante ha distribuido la totalidad de los bienes mediante legados. Al declarar la vacancia, el juez debe designar un curador de los bienes. La declaración de vacancia se inscribe en los registros que corresponden, por oficio judicial.", plainLanguageExplanation: "Establece el régimen de declaración de vacancia. A pedido de cualquier interesado o del Ministerio Público, se debe declarar vacante la herencia si no hay herederos aceptantes ni el causante ha distribuido la totalidad de los bienes mediante legados.", practicalEffects: ['En la práctica, este artículo rige declaración de vacancia. A pedido de cualquier interesado o del Ministerio Público, se debe declarar vacante la herencia si no hay herederos aceptantes ni el causante ha distr'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['declaracin', 'vacancia', 'articulo 2441'], segments: [], amendments: [] },
  { id: 'ccyc-art-2442', lawId: 'codigo-civil-comercial', number: '2442', order: 2442, title: "Funciones del curador", text: "Funciones del curador. El curador debe recibir los bienes bajo inventario. Debe proceder al pago de las deudas y legados, previa autorización judicial. A tal efecto, a falta de dinero suficiente en la herencia, debe hacer tasar los bienes y liquidarlos en la medida necesaria. Debe rendición de cuentas al Estado o a los Estados que reciben los bienes.", plainLanguageExplanation: "Establece el régimen de funciones del curador. El curador debe recibir los bienes bajo inventario.", practicalEffects: ['En la práctica, este artículo rige funciones del curador. El curador debe recibir los bienes bajo inventario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['funciones', 'curador', 'articulo 2442'], segments: [], amendments: [] },
  { id: 'ccyc-art-2443', lawId: 'codigo-civil-comercial', number: '2443', order: 2443, title: "Conclusión de la liquidación", text: "Conclusión de la liquidación. Concluida la liquidación, el juez debe mandar entregar los bienes al Estado que corresponde. Quien reclama posteriormente derechos hereditarios debe promover la petición de herencia. En tal caso, debe tomar los bienes en la situación en que se encuentran, y se considera al Estado como poseedor de buena fe. TITULO X Porción legítima", plainLanguageExplanation: "Establece el régimen de conclusión de la liquidación. Concluida la liquidación, el juez debe mandar entregar los bienes al Estado que corresponde.", practicalEffects: ['En la práctica, este artículo rige conclusión de la liquidación. Concluida la liquidación, el juez debe mandar entregar los bienes al Estado que corresponde.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conclusin', 'liquidacin', 'articulo 2443'], segments: [], amendments: [] },
  { id: 'ccyc-art-2444', lawId: 'codigo-civil-comercial', number: '2444', order: 2444, title: "Legitimarios", text: "Legitimarios. Tienen una porción legítima de la que no pueden ser privados por testamento ni por actos de disposición entre vivos a título gratuito, los descendientes, los ascendientes y el cónyuge.", plainLanguageExplanation: "Establece el régimen de legitimarios. Tienen una porción legítima de la que no pueden ser privados por testamento ni por actos de disposición entre vivos a título gratuito, los descendientes, los ascendientes y el cónyuge.", practicalEffects: ['En la práctica, este artículo rige legitimarios. Tienen una porción legítima de la que no pueden ser privados por testamento ni por actos de disposición entre vivos a título gratuito, los descendient'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legitimariosarticulo 2444'], segments: [], amendments: [] },
  { id: 'ccyc-art-2445', lawId: 'codigo-civil-comercial', number: '2445', order: 2445, title: "Porciones legítimas", text: "Porciones legítimas. La porción legítima de los descendientes es de dos tercios, la de los ascendientes de un medio y la del cónyuge de un medio. Dichas porciones se calculan sobre la suma del valor líquido de la herencia al tiempo de la muerte del causante más el de los bienes donados computables para cada legitimario, a la época de la partición según el estado del bien a la época de la donación. Para el cómputo de la porción de cada descendiente sólo se toman en cuenta las donaciones colacionables o reducibles, efectuadas a partir de los trescientos días anteriores a su nacimiento o, en su caso, al nacimiento del ascendiente a quien representa, y para el del cónyuge, las hechas después del matrimonio.", plainLanguageExplanation: "Establece el régimen de porciones legítimas. La porción legítima de los descendientes es de dos tercios, la de los ascendientes de un medio y la del cónyuge de un medio.", practicalEffects: ['En la práctica, este artículo rige porciones legítimas. La porción legítima de los descendientes es de dos tercios, la de los ascendientes de un medio y la del cónyuge de un medio.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['porciones', 'legtimas', 'articulo 2445'], segments: [], amendments: [] },
  { id: 'ccyc-art-2446', lawId: 'codigo-civil-comercial', number: '2446', order: 2446, title: "Concurrencia de legitimarios", text: "Concurrencia de legitimarios. Si concurren sólo descendientes o sólo ascendientes, la porción disponible se calcula según las respectivas legítimas. Si concurre el cónyuge con descendientes, la porción disponible se calcula según la legítima mayor.", plainLanguageExplanation: "Establece el régimen de concurrencia de legitimarios. Si concurren sólo descendientes o sólo ascendientes, la porción disponible se calcula según las respectivas legítimas.", practicalEffects: ['En la práctica, este artículo rige concurrencia de legitimarios. Si concurren sólo descendientes o sólo ascendientes, la porción disponible se calcula según las respectivas legítimas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['concurrencia', 'legitimarios', 'articulo 2446'], segments: [], amendments: [] },
  { id: 'ccyc-art-2447', lawId: 'codigo-civil-comercial', number: '2447', order: 2447, title: "Protección", text: "Protección. El testador no puede imponer gravamen ni condición alguna a las porciones legítimas; si lo hace, se tienen por no escritas.", plainLanguageExplanation: "Establece el régimen de protección. El testador no puede imponer gravamen ni condición alguna a las porciones legítimas; si lo hace, se tienen por no escritas.", practicalEffects: ['En la práctica, este artículo rige protección. El testador no puede imponer gravamen ni condición alguna a las porciones legítimas; si lo hace, se tienen por no escritas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['proteccinarticulo 2447'], segments: [], amendments: [] },
  { id: 'ccyc-art-2448', lawId: 'codigo-civil-comercial', number: '2448', order: 2448, title: "Mejora a favor de heredero con discapacidad", text: "Mejora a favor de heredero con discapacidad. El causante puede disponer, por el medio que estime conveniente, incluso mediante un fideicomiso, además de la porción disponible, de un tercio de las porciones legítimas para aplicarlas como mejora estricta a descendientes o ascendientes con discapacidad. A estos efectos, se considera persona con discapacidad, a toda persona que padece una alteración funcional permanente o prolongada, física o mental, que en relación a su edad y medio social implica desventajas considerables para su integración familiar, social, educacional o laboral.", plainLanguageExplanation: "Establece el régimen de mejora a favor de heredero con discapacidad. El causante puede disponer, por el medio que estime conveniente, incluso mediante un fideicomiso, además de la porción disponible, de un tercio de las porciones legítimas para aplicarlas como mejora estricta a descendientes o ascendientes con discapacidad.", practicalEffects: ['En la práctica, este artículo rige mejora a favor de heredero con discapacidad. El causante puede disponer, por el medio que estime conveniente, incluso mediante un fideicomiso, además de la porción disponible, de un tercio de las'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mejora', 'favor', 'heredero', 'discapacidad', 'articulo 2448'], segments: [], amendments: [] },
  { id: 'ccyc-art-2449', lawId: 'codigo-civil-comercial', number: '2449', order: 2449, title: "Irrenunciabilidad", text: "Irrenunciabilidad. Es irrenunciable la porción legítima de una sucesión aún no abierta.", plainLanguageExplanation: "Establece el régimen de irrenunciabilidad. Es irrenunciable la porción legítima de una sucesión aún no abierta.", practicalEffects: ['En la práctica, este artículo rige irrenunciabilidad. Es irrenunciable la porción legítima de una sucesión aún no abierta.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['irrenunciabilidadarticulo 2449'], segments: [], amendments: [] },
  { id: 'ccyc-art-2450', lawId: 'codigo-civil-comercial', number: '2450', order: 2450, title: "Acción de entrega de la legítima", text: "Acción de entrega de la legítima. El legitimario preterido tiene acción para que se le entregue su porción legítima, a título de heredero de cuota. También la tiene el legitimario cuando el difunto no deja bienes pero ha efectuado donaciones.", plainLanguageExplanation: "Establece el régimen de acción de entrega de la legítima. El legitimario preterido tiene acción para que se le entregue su porción legítima, a título de heredero de cuota.", practicalEffects: ['En la práctica, este artículo rige acción de entrega de la legítima. El legitimario preterido tiene acción para que se le entregue su porción legítima, a título de heredero de cuota.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accin', 'entrega', 'legtima', 'articulo 2450'], segments: [], amendments: [] },
  { id: 'ccyc-art-2451', lawId: 'codigo-civil-comercial', number: '2451', order: 2451, title: "Acción de complemento", text: "Acción de complemento. El legitimario a quien el testador le ha dejado, por cualquier título, menos de su porción legítima, sólo puede pedir su complemento.", plainLanguageExplanation: "Establece el régimen de acción de complemento. El legitimario a quien el testador le ha dejado, por cualquier título, menos de su porción legítima, sólo puede pedir su complemento.", practicalEffects: ['En la práctica, este artículo rige acción de complemento. El legitimario a quien el testador le ha dejado, por cualquier título, menos de su porción legítima, sólo puede pedir su complemento.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accin', 'complemento', 'articulo 2451'], segments: [], amendments: [] },
  { id: 'ccyc-art-2452', lawId: 'codigo-civil-comercial', number: '2452', order: 2452, title: "Reducción de disposiciones testamentarias", text: "Reducción de disposiciones testamentarias. A fin de recibir o complementar su porción, el legitimario afectado puede pedir la reducción de las instituciones de herederos de cuota y de los legados, en ese orden. Los legados se reducen en el mismo orden establecido en el segundo párrafo del artículo 2358.", plainLanguageExplanation: "Establece el régimen de reducción de disposiciones testamentarias. A fin de recibir o complementar su porción, el legitimario afectado puede pedir la reducción de las instituciones de herederos de cuota y de los legados, en ese orden.", practicalEffects: ['En la práctica, este artículo rige reducción de disposiciones testamentarias. A fin de recibir o complementar su porción, el legitimario afectado puede pedir la reducción de las instituciones de herederos de cuota y de los legados, en ese orden.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reduccin', 'disposiciones', 'testamentarias', 'articulo 2452'], segments: [], amendments: [] },
  { id: 'ccyc-art-2453', lawId: 'codigo-civil-comercial', number: '2453', order: 2453, title: "Reducción de donaciones", text: "Reducción de donaciones. Si la reducción de las disposiciones testamentarias no es suficiente para que quede cubierta la porción legítima, el heredero legitimario puede pedir la reducción de las donaciones hechas por el causante. Se reduce primero la última donación, y luego las demás en orden inverso a sus fechas, hasta salvar el derecho del reclamante. Las de igual fecha se reducen a prorrata.", plainLanguageExplanation: "Establece el régimen de reducción de donaciones. Si la reducción de las disposiciones testamentarias no es suficiente para que quede cubierta la porción legítima, el heredero legitimario puede pedir la reducción de las donaciones hechas por el causante.", practicalEffects: ['En la práctica, este artículo rige reducción de donaciones. Si la reducción de las disposiciones testamentarias no es suficiente para que quede cubierta la porción legítima, el heredero legitimario puede pedir'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reduccin', 'donaciones', 'articulo 2453'], segments: [], amendments: [] },
  { id: 'ccyc-art-2454', lawId: 'codigo-civil-comercial', number: '2454', order: 2454, title: "Efectos de la reducción de las donaciones", text: "Efectos de la reducción de las donaciones. Si la reducción es total, la donación queda resuelta. Si es parcial, por afectar sólo en parte la legítima, y el bien donado es divisible, se lo divide entre el legitimario y el donatario. Si es indivisible, la cosa debe quedar para quien le corresponde una porción mayor, con un crédito a favor de la otra parte por el valor de su derecho. En todo caso, el donatario puede impedir la resolución entregando al legitimario la suma de dinero necesaria para completar el valor de su porción legítima. El donatario es deudor desde la notificación de la demanda, de los frutos o, en caso de formular la opción prevista en el párrafo anterior, de intereses.", plainLanguageExplanation: "Establece el régimen de efectos de la reducción de las donaciones. Si la reducción es total, la donación queda resuelta.", practicalEffects: ['En la práctica, este artículo rige efectos de la reducción de las donaciones. Si la reducción es total, la donación queda resuelta.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectos', 'reduccin', 'donaciones', 'articulo 2454'], segments: [], amendments: [] },
  { id: 'ccyc-art-2455', lawId: 'codigo-civil-comercial', number: '2455', order: 2455, title: "Perecimiento de lo donado", text: "Perecimiento de lo donado. Si el bien donado perece por culpa del donatario, éste debe su valor. Si perece sin su culpa, el valor de lo donado no se computa para el cálculo de la porción legítima. Si perece parcialmente por su culpa, debe la diferencia de valor; y si perece parcialmente sin su culpa, se computa el valor subsistente.", plainLanguageExplanation: "Establece el régimen de perecimiento de lo donado. Si el bien donado perece por culpa del donatario, éste debe su valor.", practicalEffects: ['En la práctica, este artículo rige perecimiento de lo donado. Si el bien donado perece por culpa del donatario, éste debe su valor.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['perecimiento', 'donado', 'articulo 2455'], segments: [], amendments: [] },
  { id: 'ccyc-art-2456', lawId: 'codigo-civil-comercial', number: '2456', order: 2456, title: "Insolvencia del donatario", text: "Insolvencia del donatario. En caso de insolvencia de alguno de los donatarios e imposibilidad de ejercer la acción reipersecutoria a que se refiere el artículo 2458, la acción de reducción puede ser ejercida contra los donatarios de fecha anterior.", plainLanguageExplanation: "Establece el régimen de insolvencia del donatario. En caso de insolvencia de alguno de los donatarios e imposibilidad de ejercer la acción reipersecutoria a que se refiere el artículo 2458, la acción de reducción puede ser ejercida contra los donatarios de fecha anterior.", practicalEffects: ['En la práctica, este artículo rige insolvencia del donatario. En caso de insolvencia de alguno de los donatarios e imposibilidad de ejercer la acción reipersecutoria a que se refiere el artículo 2458, la acción d'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['insolvencia', 'donatario', 'articulo 2456'], segments: [], amendments: [] },
  { id: 'ccyc-art-2457', lawId: 'codigo-civil-comercial', number: '2457', order: 2457, title: "Derechos reales constituidos por el donatario", text: "Derechos reales constituidos por el donatario. La reducción extingue con relación al legitimario, los derechos reales constituidos por el donatario o por sus sucesores. Sin embargo, la reducción declarada por los jueces, no afectará la validez de los derechos reales sobre bienes registrables constituidos o transmitidos por el donatario a favor de terceros de buena fe y a título oneroso. (Artículo sustituido por art. 2º de la Ley Nº 27.587 B.O. 16/12/2020)", plainLanguageExplanation: "Establece el régimen de derechos reales constituidos por el donatario. La reducción extingue con relación al legitimario, los derechos reales constituidos por el donatario o por sus sucesores.", practicalEffects: ['En la práctica, este artículo rige derechos reales constituidos por el donatario. La reducción extingue con relación al legitimario, los derechos reales constituidos por el donatario o por sus sucesores.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos', 'reales', 'constituidos', 'donatario', 'articulo 2457'], segments: [], amendments: [] },
  { id: 'ccyc-art-2458', lawId: 'codigo-civil-comercial', number: '2458', order: 2458, title: "Acción reipersecutoria", text: "Acción reipersecutoria. Salvo lo dispuesto en el artículo anterior, el legitimario puede perseguir contra terceros adquirentes los bienes registrables. El donatario y el sub adquirente demandado, en su caso, pueden desinteresar al legitimario satisfaciendo en dinero el perjuicio a la cuota legítima. (Artículo sustituido por art. 3º de la Ley Nº 27.587 B.O. 16/12/2020)", plainLanguageExplanation: "Establece el régimen de acción reipersecutoria. Salvo lo dispuesto en el artículo anterior, el legitimario puede perseguir contra terceros adquirentes los bienes registrables.", practicalEffects: ['En la práctica, este artículo rige acción reipersecutoria. Salvo lo dispuesto en el artículo anterior, el legitimario puede perseguir contra terceros adquirentes los bienes registrables.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accin', 'reipersecutoria', 'articulo 2458'], segments: [], amendments: [] },
  { id: 'ccyc-art-2459', lawId: 'codigo-civil-comercial', number: '2459', order: 2459, title: "Prescripción adquisitiva", text: "Prescripción adquisitiva. En cualquier caso, la acción de reducción no procede contra el donatario ni contra el sub adquirente que han poseído la cosa donada durante diez (10) años computados desde la adquisición de la posesión. Se aplica el artículo 1901. No obstará la buena fe del poseedor el conocimiento de la existencia de la donación. (Artículo sustituido por art. 4º de la Ley Nº 27.587 B.O. 16/12/2020)", plainLanguageExplanation: "Establece el régimen de prescripción adquisitiva. En cualquier caso, la acción de reducción no procede contra el donatario ni contra el sub adquirente que han poseído la cosa donada durante diez (10) años computados desde la adquisición de la posesión.", practicalEffects: ['En la práctica, este artículo rige prescripción adquisitiva. En cualquier caso, la acción de reducción no procede contra el donatario ni contra el sub adquirente que han poseído la cosa donada durante diez (10)'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prescripcin', 'adquisitiva', 'articulo 2459'], segments: [], amendments: [] },
  { id: 'ccyc-art-2460', lawId: 'codigo-civil-comercial', number: '2460', order: 2460, title: "Constitución de usufructo, uso, habitación o renta vitalicia", text: "Constitución de usufructo, uso, habitación o renta vitalicia. Si la disposición gratuita entre vivos o el legado son de usufructo, uso, habitación, o renta vitalicia, el legitimario o, en su caso, todos los legitimarios de común acuerdo, pueden optar entre cumplirlo o entregar al beneficiario la porción disponible.", plainLanguageExplanation: "Establece el régimen de constitución de usufructo, uso, habitación o renta vitalicia. Si la disposición gratuita entre vivos o el legado son de usufructo, uso, habitación, o renta vitalicia, el legitimario o, en su caso, todos los legitimarios de común acuerdo, pueden optar entre cumplirlo o entregar al beneficiario la porción disponible.", practicalEffects: ['En la práctica, este artículo rige constitución de usufructo, uso, habitación o renta vitalicia. Si la disposición gratuita entre vivos o el legado son de usufructo, uso, habitación, o renta vitalicia, el legitimario o, en su caso, todos los legit'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['constitucin', 'usufructo', 'uso', 'habitacin', 'renta', 'vitalicia', 'articulo 2460'], segments: [], amendments: [] },
  { id: 'ccyc-art-2461', lawId: 'codigo-civil-comercial', number: '2461', order: 2461, title: "Transmisión de bienes a legitimarios", text: "Transmisión de bienes a legitimarios. Si por acto entre vivos a título oneroso el causante transmite a alguno de los legitimarios la propiedad de bienes con reserva de usufructo, uso o habitación, o con la contraprestación de una renta vitalicia, se presume sin admitir prueba en contrario la gratuidad del acto y la intención de mejorar al beneficiario. Sin embargo, se deben deducir del valor de lo donado las sumas que el adquirente demuestre haber efectivamente pagado. El valor de los bienes debe ser imputado a la porción disponible y el excedente es objeto de colación. Esta imputación y esta colación no pueden ser demandadas por los legitimarios que consintieron en la enajenación, sea onerosa o gratuita, con algunas de las modalidades indicadas. TITULO XI Sucesiones testamentarias CAPITULO 1 Disposiciones generales", plainLanguageExplanation: "Establece el régimen de transmisión de bienes a legitimarios. Si por acto entre vivos a título oneroso el causante transmite a alguno de los legitimarios la propiedad de bienes con reserva de usufructo, uso o habitación, o con la contraprestación de una renta vitalicia, se presume sin admitir prueba en contrario la gratuidad del acto y la i", practicalEffects: ['En la práctica, este artículo rige transmisión de bienes a legitimarios. Si por acto entre vivos a título oneroso el causante transmite a alguno de los legitimarios la propiedad de bienes con reserva de usufructo, uso o hab'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['transmisin', 'bienes', 'legitimarios', 'articulo 2461'], segments: [], amendments: [] },
  { id: 'ccyc-art-2462', lawId: 'codigo-civil-comercial', number: '2462', order: 2462, title: "Testamento", text: "Testamento. Las personas humanas pueden disponer libremente de sus bienes para después de su muerte, respetando las porciones legítimas establecidas en el Título X de este Libro, mediante testamento otorgado con las solemnidades legales; ese acto también puede incluir disposiciones extrapatrimoniales.", plainLanguageExplanation: "Establece el régimen de testamento. Las personas humanas pueden disponer libremente de sus bienes para después de su muerte, respetando las porciones legítimas establecidas en el Título X de este Libro, mediante testamento otorgado con las solemnidades legales; ese acto también puede incluir disposiciones extrapatr", practicalEffects: ['En la práctica, este artículo rige testamento. Las personas humanas pueden disponer libremente de sus bienes para después de su muerte, respetando las porciones legítimas establecidas en el Título'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['testamentoarticulo 2462'], segments: [], amendments: [] },
  { id: 'ccyc-art-2463', lawId: 'codigo-civil-comercial', number: '2463', order: 2463, title: "Reglas aplicables", text: "Reglas aplicables. Las reglas establecidas para los actos jurídicos se aplican a los testamentos en cuanto no sean alteradas por las disposiciones de este Título.", plainLanguageExplanation: "Establece el régimen de reglas aplicables. Las reglas establecidas para los actos jurídicos se aplican a los testamentos en cuanto no sean alteradas por las disposiciones de este Título.", practicalEffects: ['En la práctica, este artículo rige reglas aplicables. Las reglas establecidas para los actos jurídicos se aplican a los testamentos en cuanto no sean alteradas por las disposiciones de este Título.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reglas', 'aplicables', 'articulo 2463'], segments: [], amendments: [] },
  { id: 'ccyc-art-2464', lawId: 'codigo-civil-comercial', number: '2464', order: 2464, title: "Edad para testar", text: "Edad para testar. Pueden testar las personas mayores de edad al tiempo del acto.", plainLanguageExplanation: "Establece el régimen de edad para testar. Pueden testar las personas mayores de edad al tiempo del acto.", practicalEffects: ['En la práctica, este artículo rige edad para testar. Pueden testar las personas mayores de edad al tiempo del acto.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['edad', 'para', 'testar', 'articulo 2464'], segments: [], amendments: [] },
  { id: 'ccyc-art-2465', lawId: 'codigo-civil-comercial', number: '2465', order: 2465, title: "Expresión personal de la voluntad del testador", text: "Expresión personal de la voluntad del testador. Las disposiciones testamentarias deben ser la expresión directa de la voluntad del testador, y bastarse a sí mismas. La facultad de testar es indelegable. Las disposiciones testamentarias no pueden dejarse al arbitrio de un tercero. No es válido el testamento otorgado conjuntamente por dos o más personas.", plainLanguageExplanation: "Establece el régimen de expresión personal de la voluntad del testador. Las disposiciones testamentarias deben ser la expresión directa de la voluntad del testador, y bastarse a sí mismas.", practicalEffects: ['En la práctica, este artículo rige expresión personal de la voluntad del testador. Las disposiciones testamentarias deben ser la expresión directa de la voluntad del testador, y bastarse a sí mismas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['expresin', 'personal', 'voluntad', 'testador', 'articulo 2465'], segments: [], amendments: [] },
  { id: 'ccyc-art-2466', lawId: 'codigo-civil-comercial', number: '2466', order: 2466, title: "Ley que rige la validez del testamento", text: "Ley que rige la validez del testamento. El contenido del testamento, su validez o nulidad, se juzga según la ley vigente al momento de la muerte del testador.", plainLanguageExplanation: "Establece el régimen de ley que rige la validez del testamento. El contenido del testamento, su validez o nulidad, se juzga según la ley vigente al momento de la muerte del testador.", practicalEffects: ['En la práctica, este artículo rige ley que rige la validez del testamento. El contenido del testamento, su validez o nulidad, se juzga según la ley vigente al momento de la muerte del testador.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['rige', 'validez', 'testamento', 'articulo 2466'], segments: [], amendments: [] },
  { id: 'ccyc-art-2467', lawId: 'codigo-civil-comercial', number: '2467', order: 2467, title: "Nulidad del testamento y de disposiciones testamentarias", text: "Nulidad del testamento y de disposiciones testamentarias. Es nulo el testamento o, en su caso, la disposición testamentaria: a) por violar una prohibición legal; b) por defectos de forma; c) por haber sido otorgado por persona privada de la razón en el momento de testar. La falta de razón debe ser demostrada por quien impugna el acto; d) por haber sido otorgado por persona judicialmente declarada incapaz. Sin embargo, ésta puede otorgar testamento en intervalos lúcidos que sean suficientemente ciertos como para asegurar que la enfermedad ha cesado por entonces; e) por ser el testador una persona que padece limitaciones en su aptitud para comunicarse en forma oral y, además, no saber leer ni escribir, excepto que lo haga por escritura pública, con la participación de un intérprete en el acto; f) por haber sido otorgado con error, dolo o violencia; g) por favorecer a persona incierta, a menos que por alguna circunstancia pueda llegar a ser cierta.", plainLanguageExplanation: "Establece el régimen de nulidad del testamento y de disposiciones testamentarias. Es nulo el testamento o, en su caso, la disposición testamentaria: a) por violar una prohibición legal; b) por defectos de forma; c) por haber sido otorgado por persona privada de la razón en el momento de testar.", practicalEffects: ['En la práctica, este artículo rige nulidad del testamento y de disposiciones testamentarias. Es nulo el testamento o, en su caso, la disposición testamentaria: a) por violar una prohibición legal; b) por defectos de forma; c) por haber sido ot'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['nulidad', 'testamento', 'disposiciones', 'testamentarias', 'articulo 2467'], segments: [], amendments: [] },
  { id: 'ccyc-art-2468', lawId: 'codigo-civil-comercial', number: '2468', order: 2468, title: "Condición y cargo prohibidos", text: "Condición y cargo prohibidos. Las condiciones y cargos constituidos por hechos imposibles, prohibidos por la ley, o contrarios a la moral, son nulos pero no afectan la validez de las disposiciones sujetas a ellos.", plainLanguageExplanation: "Establece el régimen de condición y cargo prohibidos. Las condiciones y cargos constituidos por hechos imposibles, prohibidos por la ley, o contrarios a la moral, son nulos pero no afectan la validez de las disposiciones sujetas a ellos.", practicalEffects: ['En la práctica, este artículo rige condición y cargo prohibidos. Las condiciones y cargos constituidos por hechos imposibles, prohibidos por la ley, o contrarios a la moral, son nulos pero no afectan la validez de l'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['condicin', 'cargo', 'prohibidos', 'articulo 2468'], segments: [], amendments: [] },
  { id: 'ccyc-art-2469', lawId: 'codigo-civil-comercial', number: '2469', order: 2469, title: "Acción de nulidad", text: "Acción de nulidad. Cualquier interesado puede demandar la nulidad del testamento o de alguna de sus cláusulas a menos que, habiéndolo conocido, haya ratificado las disposiciones testamentarias o las haya cumplido espontáneamente.", plainLanguageExplanation: "Establece el régimen de acción de nulidad. Cualquier interesado puede demandar la nulidad del testamento o de alguna de sus cláusulas a menos que, habiéndolo conocido, haya ratificado las disposiciones testamentarias o las haya cumplido espontáneamente.", practicalEffects: ['En la práctica, este artículo rige acción de nulidad. Cualquier interesado puede demandar la nulidad del testamento o de alguna de sus cláusulas a menos que, habiéndolo conocido, haya ratificado las dispo'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accin', 'nulidad', 'articulo 2469'], segments: [], amendments: [] },
  { id: 'ccyc-art-2470', lawId: 'codigo-civil-comercial', number: '2470', order: 2470, title: "Interpretación", text: "Interpretación. Las disposiciones testamentarias deben interpretarse adecuándolas a la voluntad real del causante según el contexto total del acto. Las palabras empleadas deben ser entendidas en el sentido corriente, excepto que surja claro que el testador quiso darles un sentido técnico. Se aplican, en cuanto sean compatibles, las demás reglas de interpretación de los contratos.", plainLanguageExplanation: "Establece el régimen de interpretación. Las disposiciones testamentarias deben interpretarse adecuándolas a la voluntad real del causante según el contexto total del acto.", practicalEffects: ['En la práctica, este artículo rige interpretación. Las disposiciones testamentarias deben interpretarse adecuándolas a la voluntad real del causante según el contexto total del acto.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['interpretacinarticulo 2470'], segments: [], amendments: [] },
  { id: 'ccyc-art-2471', lawId: 'codigo-civil-comercial', number: '2471', order: 2471, title: "Obligación de denunciar la existencia del testamento", text: "Obligación de denunciar la existencia del testamento. Quien participa en el otorgamiento de un testamento o en cuyo poder se encuentra, está obligado a comunicarlo a las personas interesadas, una vez acaecida la muerte del testador. CAPITULO 2 Formas de los testamentos SECCION 1ª Disposiciones generales", plainLanguageExplanation: "Establece el régimen de obligación de denunciar la existencia del testamento. Quien participa en el otorgamiento de un testamento o en cuyo poder se encuentra, está obligado a comunicarlo a las personas interesadas, una vez acaecida la muerte del testador.", practicalEffects: ['En la práctica, este artículo rige obligación de denunciar la existencia del testamento. Quien participa en el otorgamiento de un testamento o en cuyo poder se encuentra, está obligado a comunicarlo a las personas interesadas, una vez acaecida la muerte del testador.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacin', 'denunciar', 'existencia', 'testamento', 'articulo 2471'], segments: [], amendments: [] },
  { id: 'ccyc-art-2472', lawId: 'codigo-civil-comercial', number: '2472', order: 2472, title: "Ley que rige la forma", text: "Ley que rige la forma. La ley vigente al tiempo de testar rige la forma del testamento.", plainLanguageExplanation: "Establece el régimen de ley que rige la forma. La ley vigente al tiempo de testar rige la forma del testamento.", practicalEffects: ['En la práctica, este artículo rige ley que rige la forma. La ley vigente al tiempo de testar rige la forma del testamento.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['rige', 'forma', 'articulo 2472'], segments: [], amendments: [] },
  { id: 'ccyc-art-2473', lawId: 'codigo-civil-comercial', number: '2473', order: 2473, title: "Requisitos formales", text: "Requisitos formales. El testamento puede otorgarse sólo en alguna de las formas previstas en este Código. Las formalidades determinadas por la ley para una clase de testamento no pueden extenderse a las de otra especie. La observancia de las solemnidades impuestas debe resultar del mismo testamento, sin que se pueda suplir por prueba alguna.", plainLanguageExplanation: "Establece el régimen de requisitos formales. El testamento puede otorgarse sólo en alguna de las formas previstas en este Código.", practicalEffects: ['En la práctica, este artículo rige requisitos formales. El testamento puede otorgarse sólo en alguna de las formas previstas en este Código.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitos', 'formales', 'articulo 2473'], segments: [], amendments: [] },
  { id: 'ccyc-art-2474', lawId: 'codigo-civil-comercial', number: '2474', order: 2474, title: "Sanción por inobservancia de las formas", text: "Sanción por inobservancia de las formas. La inobservancia de las formas requeridas para otorgar el testamento causa su nulidad total; pero, satisfechas las formas legales, la nulidad de una o de varias cláusulas no perjudica las restantes partes del acto. El empleo de formalidades sobreabundantes no vicia el testamento.", plainLanguageExplanation: "Establece el régimen de sanción por inobservancia de las formas. La inobservancia de las formas requeridas para otorgar el testamento causa su nulidad total; pero, satisfechas las formas legales, la nulidad de una o de varias cláusulas no perjudica las restantes partes del acto.", practicalEffects: ['En la práctica, este artículo rige sanción por inobservancia de las formas. La inobservancia de las formas requeridas para otorgar el testamento causa su nulidad total; pero, satisfechas las formas legales, la nulidad de una o'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sancin', 'inobservancia', 'formas', 'articulo 2474'], segments: [], amendments: [] },
  { id: 'ccyc-art-2475', lawId: 'codigo-civil-comercial', number: '2475', order: 2475, title: "Confirmación del testamento nulo por inobservancia de las formalidades", text: "Confirmación del testamento nulo por inobservancia de las formalidades. El testador sólo puede confirmar las disposiciones de un testamento nulo por inobservancia de las formalidades reproduciéndolas en otro testamento otorgado con los requisitos formales pertinentes.", plainLanguageExplanation: "Establece el régimen de confirmación del testamento nulo por inobservancia de las formalidades. El testador sólo puede confirmar las disposiciones de un testamento nulo por inobservancia de las formalidades reproduciéndolas en otro testamento otorgado con los requisitos formales pertinentes.", practicalEffects: ['En la práctica, este artículo rige confirmación del testamento nulo por inobservancia de las formalidades. El testador sólo puede confirmar las disposiciones de un testamento nulo por inobservancia de las formalidades reproduciéndolas en otro testamento oto'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['confirmacin', 'testamento', 'nulo', 'inobservancia', 'formalidades', 'articulo 2475'], segments: [], amendments: [] },
  { id: 'ccyc-art-2476', lawId: 'codigo-civil-comercial', number: '2476', order: 2476, title: "Firma", text: "Firma. Cuando en los testamentos se requiera la firma, debe escribírsela tal como el autor de ella acostumbra firmar los instrumentos públicos o privados. Los errores de ortografía o la omisión de letras no vician necesariamente la firma, quedando su validez librada a la apreciación judicial. SECCION 2ª Testamento ológrafo", plainLanguageExplanation: "Establece el régimen de firma. Cuando en los testamentos se requiera la firma, debe escribírsela tal como el autor de ella acostumbra firmar los instrumentos públicos o privados.", practicalEffects: ['En la práctica, este artículo rige firma. Cuando en los testamentos se requiera la firma, debe escribírsela tal como el autor de ella acostumbra firmar los instrumentos públicos o privados.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['firmaarticulo 2476'], segments: [], amendments: [] },
  { id: 'ccyc-art-2477', lawId: 'codigo-civil-comercial', number: '2477', order: 2477, title: "Requisitos", text: "Requisitos. El testamento ológrafo debe ser íntegramente escrito con los caracteres propios del idioma en que es otorgado, fechado y firmado por la mano misma del testador. La falta de alguna de estas formalidades invalida el acto, excepto que contenga enunciaciones o elementos materiales que permitan establecer la fecha de una manera cierta. La firma debe estar después de las disposiciones, y la fecha puede ponerse antes de la firma o después de ella. El error del testador sobre la fecha no perjudica la validez del acto, pero el testamento no es válido si aquél le puso voluntariamente una fecha falsa para violar una disposición de orden público. Los agregados escritos por mano extraña invalidan el testamento, sólo si han sido hechos por orden o con consentimiento del testador.", plainLanguageExplanation: "Establece el régimen de requisitos. El testamento ológrafo debe ser íntegramente escrito con los caracteres propios del idioma en que es otorgado, fechado y firmado por la mano misma del testador.", practicalEffects: ['En la práctica, este artículo rige requisitos. El testamento ológrafo debe ser íntegramente escrito con los caracteres propios del idioma en que es otorgado, fechado y firmado por la mano misma del testador.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitosarticulo 2477'], segments: [], amendments: [] },
  { id: 'ccyc-art-2478', lawId: 'codigo-civil-comercial', number: '2478', order: 2478, title: "Discontinuidad", text: "Discontinuidad. No es indispensable redactar el testamento ológrafo de una sola vez ni en la misma fecha. El testador puede consignar sus disposiciones en épocas diferentes, sea fechándolas y firmándolas por separado, o poniendo a todas ellas la fecha y la firma el día en que termine el testamento. SECCION 3ª Testamento por acto público", plainLanguageExplanation: "Establece el régimen de discontinuidad. No es indispensable redactar el testamento ológrafo de una sola vez ni en la misma fecha.", practicalEffects: ['En la práctica, este artículo rige discontinuidad. No es indispensable redactar el testamento ológrafo de una sola vez ni en la misma fecha.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['discontinuidadarticulo 2478'], segments: [], amendments: [] },
  { id: 'ccyc-art-2479', lawId: 'codigo-civil-comercial', number: '2479', order: 2479, title: "Requisitos", text: "Requisitos. El testamento por acto público se otorga mediante escritura pública, ante el escribano autorizante y dos testigos hábiles, cuyo nombre y domicilio se deben consignar en la escritura. El testador puede dar al escribano sus disposiciones ya escritas o sólo darle por escrito o verbalmente las que el testamento debe contener para que las redacte en la forma ordinaria. En ningún caso las instrucciones escritas pueden ser invocadas contra el contenido de la escritura pública. Concluida la redacción del testamento, se procede a su lectura y firma por los testigos y el testador. Los testigos deben asistir desde el comienzo hasta el fin del acto sin interrupción, lo que debe hacer constar el escribano. A esta clase de testamento se aplican las disposiciones de los artículos 299 y siguientes.", plainLanguageExplanation: "Establece el régimen de requisitos. El testamento por acto público se otorga mediante escritura pública, ante el escribano autorizante y dos testigos hábiles, cuyo nombre y domicilio se deben consignar en la escritura.", practicalEffects: ['En la práctica, este artículo rige requisitos. El testamento por acto público se otorga mediante escritura pública, ante el escribano autorizante y dos testigos hábiles, cuyo nombre y domicilio se deben consignar en la escritura.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitosarticulo 2479'], segments: [], amendments: [] },
  { id: 'ccyc-art-2480', lawId: 'codigo-civil-comercial', number: '2480', order: 2480, title: "Firma a ruego", text: "Firma a ruego. Si el testador no sabe firmar, o no puede hacerlo, puede hacerlo por él otra persona o alguno de los testigos. En este caso los dos testigos deben saber firmar. Si el testador sabe firmar y manifiesta lo contrario, el testamento no es válido. Si sabiendo firmar, no puede hacerlo, el escribano debe explicitar la causa por la cual no puede firmar el testador.", plainLanguageExplanation: "Establece el régimen de firma a ruego. Si el testador no sabe firmar, o no puede hacerlo, puede hacerlo por él otra persona o alguno de los testigos.", practicalEffects: ['En la práctica, este artículo rige firma a ruego. Si el testador no sabe firmar, o no puede hacerlo, puede hacerlo por él otra persona o alguno de los testigos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['firma', 'ruego', 'articulo 2480'], segments: [], amendments: [] },
  { id: 'ccyc-art-2481', lawId: 'codigo-civil-comercial', number: '2481', order: 2481, title: "Testigos", text: "Testigos. Pueden ser testigos de los testamentos las personas capaces al tiempo de otorgarse el acto. No pueden serlo, además de los enunciados en el artículo 295, los ascendientes, los descendientes, el cónyuge ni el conviviente del testador, ni los albaceas, tutores o curadores designados en el testamento, ni los beneficiarios de alguna de sus disposiciones. El testamento en que interviene un testigo incapaz o inhábil al efecto no es válido si, excluido éste, no quedan otros en número suficiente. CAPITULO 3 Inhabilidad para suceder por testamento", plainLanguageExplanation: "Establece el régimen de testigos. Pueden ser testigos de los testamentos las personas capaces al tiempo de otorgarse el acto.", practicalEffects: ['En la práctica, este artículo rige testigos. Pueden ser testigos de los testamentos las personas capaces al tiempo de otorgarse el acto.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['testigosarticulo 2481'], segments: [], amendments: [] },
  { id: 'ccyc-art-2482', lawId: 'codigo-civil-comercial', number: '2482', order: 2482, title: "Personas que no pueden suceder", text: "Personas que no pueden suceder. No pueden suceder por testamento: a) los tutores y curadores a sus pupilos, si éstos mueren durante la tutela o curatela o antes de ser aprobadas las cuentas definitivas de la administración; b) el escribano y los testigos ante quienes se haya otorgado el testamento, por el acto en el cual han intervenido; c) los ministros de cualquier culto y los líderes o conductores espirituales que hayan asistido al causante en su última enfermedad.", plainLanguageExplanation: "Establece el régimen de personas que no pueden suceder. No pueden suceder por testamento: a) los tutores y curadores a sus pupilos, si éstos mueren durante la tutela o curatela o antes de ser aprobadas las cuentas definitivas de la administración; b) el escribano y los testigos ante quienes se haya otorgado el testamento, por el acto", practicalEffects: ['En la práctica, este artículo rige personas que no pueden suceder. No pueden suceder por testamento: a) los tutores y curadores a sus pupilos, si éstos mueren durante la tutela o curatela o antes de ser aprobadas las'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['personas', 'pueden', 'suceder', 'articulo 2482'], segments: [], amendments: [] },
  { id: 'ccyc-art-2483', lawId: 'codigo-civil-comercial', number: '2483', order: 2483, title: "Sanción", text: "Sanción. Las disposiciones testamentarias a favor de personas que no pueden suceder por testamento son de ningún valor, aun cuando se hagan a nombre de personas interpuestas. Se reputan tales, sin admitir prueba en contrario, los ascendientes, los descendientes, y el cónyuge o conviviente de la persona impedida de suceder. El fraude a la ley puede ser probado por cualquier medio. Los inhábiles para suceder por testamento que se encuentran en posesión de los bienes dejados por el testador son considerados de mala fe. CAPITULO 4 Institución y sustitución de herederos y legatarios", plainLanguageExplanation: "Establece el régimen de sanción. Las disposiciones testamentarias a favor de personas que no pueden suceder por testamento son de ningún valor, aun cuando se hagan a nombre de personas interpuestas.", practicalEffects: ['En la práctica, este artículo rige sanción. Las disposiciones testamentarias a favor de personas que no pueden suceder por testamento son de ningún valor, aun cuando se hagan a nombre de personas interpuestas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sancinarticulo 2483'], segments: [], amendments: [] },
  { id: 'ccyc-art-2484', lawId: 'codigo-civil-comercial', number: '2484', order: 2484, title: "Principio general", text: "Principio general. La institución de herederos y legatarios sólo puede ser hecha en el testamento y no debe dejar dudas sobre la identidad de la persona instituida.", plainLanguageExplanation: "Establece el régimen de principio general. La institución de herederos y legatarios sólo puede ser hecha en el testamento y no debe dejar dudas sobre la identidad de la persona instituida.", practicalEffects: ['En la práctica, este artículo rige principio general. La institución de herederos y legatarios sólo puede ser hecha en el testamento y no debe dejar dudas sobre la identidad de la persona instituida.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['principio', 'general', 'articulo 2484'], segments: [], amendments: [] },
  { id: 'ccyc-art-2485', lawId: 'codigo-civil-comercial', number: '2485', order: 2485, title: "Casos especiales", text: "Casos especiales. La institución a los parientes se entiende hecha a los de grado más próximo, según el orden de la sucesión intestada y teniendo en cuenta el derecho de representación. Si a la fecha del testamento hay un solo pariente en el grado más próximo, se entienden llamados al mismo tiempo los del grado siguiente. La institución a favor de simples asociaciones se entiende hecha a favor de las autoridades superiores respectivas del lugar del último domicilio del testador con cargo de aplicar los bienes a los fines indicados por el causante. La institución a los pobres se entiende hecha al Estado municipal del lugar del último domicilio del testador o la Ciudad Autónoma de Buenos Aires, en su caso, con cargo de aplicar los bienes a fines de asistencia social. La institución a favor del alma del testador o de otras personas se entiende hecha a la autoridad superior de la religión a la cual pertenece el testador, con cargo de aplicar los bienes a sufragios y fines de asistencia social.", plainLanguageExplanation: "Establece el régimen de casos especiales. La institución a los parientes se entiende hecha a los de grado más próximo, según el orden de la sucesión intestada y teniendo en cuenta el derecho de representación.", practicalEffects: ['En la práctica, este artículo rige casos especiales. La institución a los parientes se entiende hecha a los de grado más próximo, según el orden de la sucesión intestada y teniendo en cuenta el derecho de representación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['casos', 'especiales', 'articulo 2485'], segments: [], amendments: [] },
  { id: 'ccyc-art-2486', lawId: 'codigo-civil-comercial', number: '2486', order: 2486, title: "Herederos universales", text: "Herederos universales. Los herederos instituidos sin asignación de partes suceden al causante por partes iguales y tienen vocación a todos los bienes de la herencia a los que el testador no haya dado un destino diferente. Si el testamento instituye uno o varios herederos con asignación de partes y otro u otros sin ella, a éstos corresponde el remanente de bienes después de haber sido satisfechas las porciones atribuidas por el testador. Si éstas absorben toda la herencia, se reducen proporcionalmente, de manera que cada heredero sin parte designada reciba tanto como el heredero instituido en la fracción menor.", plainLanguageExplanation: "Establece el régimen de herederos universales. Los herederos instituidos sin asignación de partes suceden al causante por partes iguales y tienen vocación a todos los bienes de la herencia a los que el testador no haya dado un destino diferente.", practicalEffects: ['En la práctica, este artículo rige herederos universales. Los herederos instituidos sin asignación de partes suceden al causante por partes iguales y tienen vocación a todos los bienes de la herencia a los que el testador no haya dado un destino diferente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['herederos', 'universales', 'articulo 2486'], segments: [], amendments: [] },
  { id: 'ccyc-art-2487', lawId: 'codigo-civil-comercial', number: '2487', order: 2487, title: "Casos de institución de herederos universales", text: "Casos de institución de herederos universales. La institución de herederos universales no requiere el empleo de términos sacramentales. La constituyen especialmente: a) la atribución de la universalidad de los bienes de la herencia, aunque se limite a la nuda propiedad; b) el legado de lo que reste después de cumplidos los demás legados; c) los legados que absorben la totalidad de los bienes, si el testador confiere a los legatarios el derecho de acrecer. El heredero instituido en uno o más bienes determinados es legatario.", plainLanguageExplanation: "Establece el régimen de casos de institución de herederos universales. La institución de herederos universales no requiere el empleo de términos sacramentales.", practicalEffects: ['En la práctica, este artículo rige casos de institución de herederos universales. La institución de herederos universales no requiere el empleo de términos sacramentales.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['casos', 'institucin', 'herederos', 'universales', 'articulo 2487'], segments: [], amendments: [] },
  { id: 'ccyc-art-2488', lawId: 'codigo-civil-comercial', number: '2488', order: 2488, title: "Herederos de cuota", text: "Herederos de cuota. Los herederos instituidos en una fracción de la herencia no tienen vocación a todos los bienes de ésta, excepto que deba entenderse que el testador ha querido conferirles ese llamado para el supuesto de que no puedan cumplirse, por cualquier causa, las demás disposiciones testamentarias. Si la adición de las fracciones consignadas en el testamento excede la unidad, se reducen proporcionalmente hasta ese límite. Si la suma de las fracciones no cubre todo el patrimonio, el remanente de los bienes corresponde a los herederos legítimos y, a falta de ellos, a los herederos instituidos en proporción a sus cuotas.", plainLanguageExplanation: "Establece el régimen de herederos de cuota. Los herederos instituidos en una fracción de la herencia no tienen vocación a todos los bienes de ésta, excepto que deba entenderse que el testador ha querido conferirles ese llamado para el supuesto de que no puedan cumplirse, por cualquier causa, las demás disposiciones testamentarias.", practicalEffects: ['En la práctica, este artículo rige herederos de cuota. Los herederos instituidos en una fracción de la herencia no tienen vocación a todos los bienes de ésta, excepto que deba entenderse que el testador ha'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['herederos', 'cuota', 'articulo 2488'], segments: [], amendments: [] },
  { id: 'ccyc-art-2489', lawId: 'codigo-civil-comercial', number: '2489', order: 2489, title: "Derecho de acrecer", text: "Derecho de acrecer. Cuando el testador instituye a varios herederos en una misma cuota, o atribuye un bien conjuntamente a varios legatarios, cada beneficiario aprovecha proporcionalmente de la parte perteneciente al heredero o legatario cuyo derecho se frustra o caduca. Los favorecidos por el acrecimiento quedan sujetos a las obligaciones y cargas que pesaban sobre la parte acrecida, excepto que sean de carácter personal. El derecho de acrecer se transmite a los herederos.", plainLanguageExplanation: "Establece el régimen de derecho de acrecer. Cuando el testador instituye a varios herederos en una misma cuota, o atribuye un bien conjuntamente a varios legatarios, cada beneficiario aprovecha proporcionalmente de la parte perteneciente al heredero o legatario cuyo derecho se frustra o caduca.", practicalEffects: ['En la práctica, este artículo rige derecho de acrecer. Cuando el testador instituye a varios herederos en una misma cuota, o atribuye un bien conjuntamente a varios legatarios, cada beneficiario aprovecha'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho', 'acrecer', 'articulo 2489'], segments: [], amendments: [] },
  { id: 'ccyc-art-2490', lawId: 'codigo-civil-comercial', number: '2490', order: 2490, title: "Legado de usufructo", text: "Legado de usufructo. La muerte del colegatario de usufructo, posterior a la del testador, no produce el acrecimiento de los otros colegatarios excepto disposición en contrario del testamento.", plainLanguageExplanation: "Establece el régimen de legado de usufructo. La muerte del colegatario de usufructo, posterior a la del testador, no produce el acrecimiento de los otros colegatarios excepto disposición en contrario del testamento.", practicalEffects: ['En la práctica, este artículo rige legado de usufructo. La muerte del colegatario de usufructo, posterior a la del testador, no produce el acrecimiento de los otros colegatarios excepto disposición en contr'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legado', 'usufructo', 'articulo 2490'], segments: [], amendments: [] },
  { id: 'ccyc-art-2491', lawId: 'codigo-civil-comercial', number: '2491', order: 2491, title: "Sustitución", text: "Sustitución. La facultad de instituir herederos o legatarios no importa el derecho de imponer un sucesor a los instituidos. La disposición que viola esta prohibición no afecta la validez de la institución, y tiene eficacia si puede valer en alguno de los dos casos del párrafo siguiente. El testador puede subrogar al instituido para el supuesto de que éste no quiera o no pueda aceptar la herencia o el legado. La sustitución establecida para uno de esos casos vale para el otro. El heredero o legatario sustituto queda sujeto a las mismas cargas y condiciones impuestas al sustituido si no aparece claramente que el testador quiso limitarlas al llamado en primer término.", plainLanguageExplanation: "Establece el régimen de sustitución. La facultad de instituir herederos o legatarios no importa el derecho de imponer un sucesor a los instituidos.", practicalEffects: ['En la práctica, este artículo rige sustitución. La facultad de instituir herederos o legatarios no importa el derecho de imponer un sucesor a los instituidos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sustitucinarticulo 2491'], segments: [], amendments: [] },
  { id: 'ccyc-art-2492', lawId: 'codigo-civil-comercial', number: '2492', order: 2492, title: "Sustitución de residuo", text: "Sustitución de residuo. No es válida la disposición del testador por la que llame a un tercero a recibir lo que reste de su herencia al morir el heredero o legatario instituido. La nulidad de esta disposición no perjudica los derechos de los instituidos.", plainLanguageExplanation: "Establece el régimen de sustitución de residuo. No es válida la disposición del testador por la que llame a un tercero a recibir lo que reste de su herencia al morir el heredero o legatario instituido.", practicalEffects: ['En la práctica, este artículo rige sustitución de residuo. No es válida la disposición del testador por la que llame a un tercero a recibir lo que reste de su herencia al morir el heredero o legatario instituido.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sustitucin', 'residuo', 'articulo 2492'], segments: [], amendments: [] },
  { id: 'ccyc-art-2493', lawId: 'codigo-civil-comercial', number: '2493', order: 2493, title: "Fideicomiso testamentario", text: "Fideicomiso testamentario. El testador puede disponer un fideicomiso sobre toda la herencia, una parte indivisa o bienes determinados, y establecer instrucciones al heredero o legatario fiduciario, conforme a los recaudos establecidos en la Sección 8º, Capítulo 30, Título IV del Libro Tercero. La constitución del fideicomiso no debe afectar la legítima de los herederos forzosos, excepto el caso previsto en el artículo 2448. CAPITULO 5 Legados", plainLanguageExplanation: "Establece el régimen de fideicomiso testamentario. El testador puede disponer un fideicomiso sobre toda la herencia, una parte indivisa o bienes determinados, y establecer instrucciones al heredero o legatario fiduciario, conforme a los recaudos establecidos en la Sección 8º, Capítulo 30, Título IV del Libro Tercero.", practicalEffects: ['En la práctica, este artículo rige fideicomiso testamentario. El testador puede disponer un fideicomiso sobre toda la herencia, una parte indivisa o bienes determinados, y establecer instrucciones al heredero o l'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fideicomiso', 'testamentario', 'articulo 2493'], segments: [], amendments: [] },
  { id: 'ccyc-art-2494', lawId: 'codigo-civil-comercial', number: '2494', order: 2494, title: "Normas aplicables", text: "Normas aplicables. El heredero está obligado a cumplir los legados hechos por el testador conforme a lo dispuesto en este Código sobre las obligaciones en general, excepto disposición expresa en contrario de este Capítulo.", plainLanguageExplanation: "Establece el régimen de normas aplicables. El heredero está obligado a cumplir los legados hechos por el testador conforme a lo dispuesto en este Código sobre las obligaciones en general, excepto disposición expresa en contrario de este Capítulo.", practicalEffects: ['En la práctica, este artículo rige normas aplicables. El heredero está obligado a cumplir los legados hechos por el testador conforme a lo dispuesto en este Código sobre las obligaciones en general, excep'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['normas', 'aplicables', 'articulo 2494'], segments: [], amendments: [] },
  { id: 'ccyc-art-2495', lawId: 'codigo-civil-comercial', number: '2495', order: 2495, title: "Legado sujeto al arbitrio de un tercero o del heredero", text: "Legado sujeto al arbitrio de un tercero o del heredero. El legado no puede dejarse al arbitrio de un tercero ni del heredero.", plainLanguageExplanation: "Establece el régimen de legado sujeto al arbitrio de un tercero o del heredero. El legado no puede dejarse al arbitrio de un tercero ni del heredero.", practicalEffects: ['En la práctica, este artículo rige legado sujeto al arbitrio de un tercero o del heredero. El legado no puede dejarse al arbitrio de un tercero ni del heredero.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legado', 'sujeto', 'arbitrio', 'tercero', 'heredero', 'articulo 2495'], segments: [], amendments: [] },
  { id: 'ccyc-art-2496', lawId: 'codigo-civil-comercial', number: '2496', order: 2496, title: "Adquisición del legado", text: "Adquisición del legado. Modalidades. El derecho al legado se adquiere a partir de la muerte del testador o, en su caso, desde el cumplimiento de la condición a que está sujeto. El legado con cargo se rige por las disposiciones relativas a las donaciones sujetas a esa modalidad.", plainLanguageExplanation: "Establece el régimen de adquisición del legado. Modalidades.", practicalEffects: ['En la práctica, este artículo rige adquisición del legado. Modalidades.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['adquisicin', 'legado', 'articulo 2496'], segments: [], amendments: [] },
  { id: 'ccyc-art-2497', lawId: 'codigo-civil-comercial', number: '2497', order: 2497, title: "Bienes que pueden ser legados", text: "Bienes que pueden ser legados. Pueden ser legados todos los bienes que están en el comercio, aun los que no existen todavía pero que existirán después. El legatario de bienes determinados es propietario de ellos desde la muerte del causante y puede ejercer todas las acciones de que aquel era titular.", plainLanguageExplanation: "Establece el régimen de bienes que pueden ser legados. Pueden ser legados todos los bienes que están en el comercio, aun los que no existen todavía pero que existirán después.", practicalEffects: ['En la práctica, este artículo rige bienes que pueden ser legados. Pueden ser legados todos los bienes que están en el comercio, aun los que no existen todavía pero que existirán después.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['bienes', 'pueden', 'legados', 'articulo 2497'], segments: [], amendments: [] },
  { id: 'ccyc-art-2498', lawId: 'codigo-civil-comercial', number: '2498', order: 2498, title: "Legado de cosa cierta y determinada", text: "Legado de cosa cierta y determinada. El legatario de cosa cierta y determinada puede reivindicarla, con citación del heredero. Debe pedir su entrega al heredero, al administrador o al albacea, aunque la tenga en su poder por cualquier título. Los gastos de entrega del legado están a cargo de la sucesión.", plainLanguageExplanation: "Establece el régimen de legado de cosa cierta y determinada. El legatario de cosa cierta y determinada puede reivindicarla, con citación del heredero.", practicalEffects: ['En la práctica, este artículo rige legado de cosa cierta y determinada. El legatario de cosa cierta y determinada puede reivindicarla, con citación del heredero.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legado', 'cosa', 'cierta', 'determinada', 'articulo 2498'], segments: [], amendments: [] },
  { id: 'ccyc-art-2499', lawId: 'codigo-civil-comercial', number: '2499', order: 2499, title: "Entrega del legado", text: "Entrega del legado. El heredero debe entregar la cosa legada en el estado en que se encuentra a la muerte del testador, con todos sus accesorios.", plainLanguageExplanation: "Establece el régimen de entrega del legado. El heredero debe entregar la cosa legada en el estado en que se encuentra a la muerte del testador, con todos sus accesorios.", practicalEffects: ['En la práctica, este artículo rige entrega del legado. El heredero debe entregar la cosa legada en el estado en que se encuentra a la muerte del testador, con todos sus accesorios.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['entrega', 'legado', 'articulo 2499'], segments: [], amendments: [] },
  { id: 'ccyc-art-2500', lawId: 'codigo-civil-comercial', number: '2500', order: 2500, title: "Legado de cosa gravada", text: "Legado de cosa gravada. El heredero no está obligado a liberar la cosa legada de las cargas que soporta. El legatario responde por las obligaciones a cuya satisfacción está afectada la cosa legada, hasta la concurrencia del valor de ésta.", plainLanguageExplanation: "Establece el régimen de legado de cosa gravada. El heredero no está obligado a liberar la cosa legada de las cargas que soporta.", practicalEffects: ['En la práctica, este artículo rige legado de cosa gravada. El heredero no está obligado a liberar la cosa legada de las cargas que soporta.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legado', 'cosa', 'gravada', 'articulo 2500'], segments: [], amendments: [] },
  { id: 'ccyc-art-2501', lawId: 'codigo-civil-comercial', number: '2501', order: 2501, title: "Legado de inmueble", text: "Legado de inmueble. El legado de un inmueble comprende las mejoras existentes, cualquiera que sea la época en que hayan sido realizadas. Los terrenos adquiridos por el testador después de testar, que constituyen una ampliación del fundo legado, se deben al legatario siempre que no sean susceptibles de explotación independiente.", plainLanguageExplanation: "Establece el régimen de legado de inmueble. El legado de un inmueble comprende las mejoras existentes, cualquiera que sea la época en que hayan sido realizadas.", practicalEffects: ['En la práctica, este artículo rige legado de inmueble. El legado de un inmueble comprende las mejoras existentes, cualquiera que sea la época en que hayan sido realizadas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legado', 'inmueble', 'articulo 2501'], segments: [], amendments: [] },
  { id: 'ccyc-art-2502', lawId: 'codigo-civil-comercial', number: '2502', order: 2502, title: "Legado de género", text: "Legado de género. El legado cuyo objeto está determinado genéricamente es válido aunque no exista cosa alguna de ese género en el patrimonio del testador. Si la elección ha sido conferida expresamente al heredero o al legatario, éstos pueden optar, respectivamente, por la cosa de peor o de mejor calidad. Si hay una sola cosa en el patrimonio del testador, con ella debe cumplirse el legado.", plainLanguageExplanation: "Establece el régimen de legado de género. El legado cuyo objeto está determinado genéricamente es válido aunque no exista cosa alguna de ese género en el patrimonio del testador.", practicalEffects: ['En la práctica, este artículo rige legado de género. El legado cuyo objeto está determinado genéricamente es válido aunque no exista cosa alguna de ese género en el patrimonio del testador.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legado', 'gnero', 'articulo 2502'], segments: [], amendments: [] },
  { id: 'ccyc-art-2503', lawId: 'codigo-civil-comercial', number: '2503', order: 2503, title: "Evicción en el legado de cosa fungible y en el legado alternativo", text: "Evicción en el legado de cosa fungible y en el legado alternativo. Si ocurre la evicción de la cosa fungible entregada al legatario, éste puede reclamar la entrega de otra de la misma especie y calidad. Si el legado es alternativo, producida la evicción del bien entregado al legatario, éste puede pedir alguno de los otros comprendidos en la alternativa.", plainLanguageExplanation: "Establece el régimen de evicción en el legado de cosa fungible y en el legado alternativo. Si ocurre la evicción de la cosa fungible entregada al legatario, éste puede reclamar la entrega de otra de la misma especie y calidad.", practicalEffects: ['En la práctica, este artículo rige evicción en el legado de cosa fungible y en el legado alternativo. Si ocurre la evicción de la cosa fungible entregada al legatario, éste puede reclamar la entrega de otra de la misma especie y calidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['eviccin', 'legado', 'cosa', 'fungible', 'alternativo', 'articulo 2503'], segments: [], amendments: [] },
  { id: 'ccyc-art-2504', lawId: 'codigo-civil-comercial', number: '2504', order: 2504, title: "Legado con determinación del lugar", text: "Legado con determinación del lugar. El legado de cosas que deben encontrarse en determinado lugar se cumple entregando la cantidad allí existente a la muerte del testador, aunque sea menor que la designada. Si es mayor, entregando la cantidad designada. Si no se encuentra cosa alguna, nada se debe. Si las cosas legadas han sido removidas temporariamente del lugar habitual de ubicación aludido en el testamento, el legado comprende las que subsistan en el patrimonio del testador hasta la concurrencia de la cantidad indicada por éste.", plainLanguageExplanation: "Establece el régimen de legado con determinación del lugar. El legado de cosas que deben encontrarse en determinado lugar se cumple entregando la cantidad allí existente a la muerte del testador, aunque sea menor que la designada.", practicalEffects: ['En la práctica, este artículo rige legado con determinación del lugar. El legado de cosas que deben encontrarse en determinado lugar se cumple entregando la cantidad allí existente a la muerte del testador, aunque sea menor que la designada.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legado', 'determinacin', 'lugar', 'articulo 2504'], segments: [], amendments: [] },
  { id: 'ccyc-art-2505', lawId: 'codigo-civil-comercial', number: '2505', order: 2505, title: "Legado de crédito", text: "Legado de crédito. Legado de liberación. El legado de un crédito o la liberación de una deuda comprende la parte del crédito o de la deuda que subsiste a la muerte del testador y los intereses desde entonces. El heredero debe entregar al legatario las constancias de la obligación que el testador tenía en su poder. La liberación de deuda no comprende las obligaciones contraídas por el legatario con posterioridad a la fecha del testamento.", plainLanguageExplanation: "Establece el régimen de legado de crédito. Legado de liberación.", practicalEffects: ['En la práctica, este artículo rige legado de crédito. Legado de liberación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legado', 'crdito', 'articulo 2505'], segments: [], amendments: [] },
  { id: 'ccyc-art-2506', lawId: 'codigo-civil-comercial', number: '2506', order: 2506, title: "Legado al acreedor", text: "Legado al acreedor. Lo que el testador legue a su acreedor no se imputa al pago de la deuda, excepto disposición expresa en contrario. El reconocimiento de una deuda hecho en el testamento se considera un legado, excepto prueba en contrario. Si el testador manda pagar lo que erróneamente cree deber, la disposición se tiene por no escrita. Si manda pagar más de lo que debe, el exceso no se considera legado.", plainLanguageExplanation: "Establece el régimen de legado al acreedor. Lo que el testador legue a su acreedor no se imputa al pago de la deuda, excepto disposición expresa en contrario.", practicalEffects: ['En la práctica, este artículo rige legado al acreedor. Lo que el testador legue a su acreedor no se imputa al pago de la deuda, excepto disposición expresa en contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legado', 'acreedor', 'articulo 2506'], segments: [], amendments: [] },
  { id: 'ccyc-art-2507', lawId: 'codigo-civil-comercial', number: '2507', order: 2507, title: "Legado de cosa ajena", text: "Legado de cosa ajena. El legado de cosa ajena no es válido, pero se convalida con la posterior adquisición de ella por el testador. El legado de cosa ajena es válido si el testador impone al heredero la obligación de adquirirla para transmitirla al legatario o a pagar a éste su justo precio si no puede obtenerla en condiciones equitativas. Si la cosa legada ha sido adquirida por el legatario antes de la apertura de la sucesión, se le debe su precio equitativo. El legado queda sin efecto si la adquisición es gratuita.", plainLanguageExplanation: "Establece el régimen de legado de cosa ajena. El legado de cosa ajena no es válido, pero se convalida con la posterior adquisición de ella por el testador.", practicalEffects: ['En la práctica, este artículo rige legado de cosa ajena. El legado de cosa ajena no es válido, pero se convalida con la posterior adquisición de ella por el testador.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legado', 'cosa', 'ajena', 'articulo 2507'], segments: [], amendments: [] },
  { id: 'ccyc-art-2508', lawId: 'codigo-civil-comercial', number: '2508', order: 2508, title: "Legado de un bien en condominio", text: "Legado de un bien en condominio. El legado de un bien cuya propiedad es común a varias personas transmite los derechos que corresponden al testador al tiempo de su muerte. El legado de un bien comprendido en una masa patrimonial común a varias personas es válido si el bien resulta adjudicado al testador antes de su muerte; en caso contrario, vale como legado de cantidad por el valor que tenía el bien al momento de la muerte del testador.", plainLanguageExplanation: "Establece el régimen de legado de un bien en condominio. El legado de un bien cuya propiedad es común a varias personas transmite los derechos que corresponden al testador al tiempo de su muerte.", practicalEffects: ['En la práctica, este artículo rige legado de un bien en condominio. El legado de un bien cuya propiedad es común a varias personas transmite los derechos que corresponden al testador al tiempo de su muerte.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legado', 'bien', 'condominio', 'articulo 2508'], segments: [], amendments: [] },
  { id: 'ccyc-art-2509', lawId: 'codigo-civil-comercial', number: '2509', order: 2509, title: "Legado de alimentos", text: "Legado de alimentos. El legado de alimentos comprende la instrucción adecuada a la condición y aptitudes del legatario, el sustento, vestido, vivienda y asistencia en las enfermedades hasta que alcance la mayoría de edad o recupere la capacidad. Si alcanzada la mayoría de edad por el legatario persiste su falta de aptitud para procurarse los alimentos, se extiende hasta que se encuentre en condiciones de hacerlo. El legado de alimentos a una persona capaz vale como legado de prestaciones periódicas en la medida dispuesta por el testador.", plainLanguageExplanation: "Establece el régimen de legado de alimentos. El legado de alimentos comprende la instrucción adecuada a la condición y aptitudes del legatario, el sustento, vestido, vivienda y asistencia en las enfermedades hasta que alcance la mayoría de edad o recupere la capacidad.", practicalEffects: ['En la práctica, este artículo rige legado de alimentos. El legado de alimentos comprende la instrucción adecuada a la condición y aptitudes del legatario, el sustento, vestido, vivienda y asistencia en las'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legado', 'alimentos', 'articulo 2509'], segments: [], amendments: [] },
  { id: 'ccyc-art-2510', lawId: 'codigo-civil-comercial', number: '2510', order: 2510, title: "Legado de pago periódico", text: "Legado de pago periódico. Cuando el legado es de cumplimiento periódico, se entiende que existen tantos legados cuantas prestaciones se deban cumplir. A partir de la muerte del testador se debe cada cuota íntegramente, con tal de que haya comenzado a transcurrir el período correspondiente, aun si el legatario fallece durante su transcurso. CAPITULO 6 Revocación y caducidad de las disposiciones testamentarias", plainLanguageExplanation: "Establece el régimen de legado de pago periódico. Cuando el legado es de cumplimiento periódico, se entiende que existen tantos legados cuantas prestaciones se deban cumplir.", practicalEffects: ['En la práctica, este artículo rige legado de pago periódico. Cuando el legado es de cumplimiento periódico, se entiende que existen tantos legados cuantas prestaciones se deban cumplir.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legado', 'pago', 'peridico', 'articulo 2510'], segments: [], amendments: [] },
  { id: 'ccyc-art-2511', lawId: 'codigo-civil-comercial', number: '2511', order: 2511, title: "Revocabilidad", text: "Revocabilidad. El testamento es revocable a voluntad del testador y no confiere a los instituidos derecho alguno hasta la apertura de la sucesión. La facultad de revocar el testamento o modificar sus disposiciones es irrenunciable e irrestringible.", plainLanguageExplanation: "Establece el régimen de revocabilidad. El testamento es revocable a voluntad del testador y no confiere a los instituidos derecho alguno hasta la apertura de la sucesión.", practicalEffects: ['En la práctica, este artículo rige revocabilidad. El testamento es revocable a voluntad del testador y no confiere a los instituidos derecho alguno hasta la apertura de la sucesión.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['revocabilidadarticulo 2511'], segments: [], amendments: [] },
  { id: 'ccyc-art-2512', lawId: 'codigo-civil-comercial', number: '2512', order: 2512, title: "Revocación expresa", text: "Revocación expresa. La revocación expresa debe ajustarse a las formalidades propias de los testamentos.", plainLanguageExplanation: "Establece el régimen de revocación expresa. La revocación expresa debe ajustarse a las formalidades propias de los testamentos.", practicalEffects: ['En la práctica, este artículo rige revocación expresa. La revocación expresa debe ajustarse a las formalidades propias de los testamentos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['revocacin', 'expresa', 'articulo 2512'], segments: [], amendments: [] },
  { id: 'ccyc-art-2513', lawId: 'codigo-civil-comercial', number: '2513', order: 2513, title: "Testamento posterior", text: "Testamento posterior. El testamento posterior revoca al anterior si no contiene su confirmación expresa, excepto que de las disposiciones del segundo resulte la voluntad del testador de mantener las del primero en todo o en parte.", plainLanguageExplanation: "Establece el régimen de testamento posterior. El testamento posterior revoca al anterior si no contiene su confirmación expresa, excepto que de las disposiciones del segundo resulte la voluntad del testador de mantener las del primero en todo o en parte.", practicalEffects: ['En la práctica, este artículo rige testamento posterior. El testamento posterior revoca al anterior si no contiene su confirmación expresa, excepto que de las disposiciones del segundo resulte la voluntad de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['testamento', 'posterior', 'articulo 2513'], segments: [], amendments: [] },
  { id: 'ccyc-art-2514', lawId: 'codigo-civil-comercial', number: '2514', order: 2514, title: "Revocación por matrimonio", text: "Revocación por matrimonio. El matrimonio contraído por el testador revoca el testamento anteriormente otorgado, excepto que en éste se instituya heredero al cónyuge o que de sus disposiciones resulte la voluntad de mantenerlas después del matrimonio.", plainLanguageExplanation: "Establece el régimen de revocación por matrimonio. El matrimonio contraído por el testador revoca el testamento anteriormente otorgado, excepto que en éste se instituya heredero al cónyuge o que de sus disposiciones resulte la voluntad de mantenerlas después del matrimonio.", practicalEffects: ['En la práctica, este artículo rige revocación por matrimonio. El matrimonio contraído por el testador revoca el testamento anteriormente otorgado, excepto que en éste se instituya heredero al cónyuge o que de sus'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['revocacin', 'matrimonio', 'articulo 2514'], segments: [], amendments: [] },
  { id: 'ccyc-art-2515', lawId: 'codigo-civil-comercial', number: '2515', order: 2515, title: "Cancelación o destrucción del testamento ológrafo", text: "Cancelación o destrucción del testamento ológrafo. El testamento ológrafo es revocado por su cancelación o destrucción hecha por el testador o por orden suya. Cuando existen varios ejemplares del testamento, éste queda revocado por la cancelación o destrucción de todos los originales, y también cuando ha quedado algún ejemplar sin ser cancelado o destruido por error, dolo o violencia sufridos por el testador. Si el testamento se encuentra total o parcialmente destruido o cancelado en casa del testador, se presume que la destrucción o cancelación es obra suya, mientras no se pruebe lo contrario. Las alteraciones casuales o provenientes de un extraño no afectan la eficacia del testamento con tal de que pueda identificarse la voluntad del testador por el testamento mismo. No se admite prueba alguna tendiente a demostrar las disposiciones de un testamento destruido antes de la muerte del testador, aunque la destrucción se haya debido a caso fortuito.", plainLanguageExplanation: "Establece el régimen de cancelación o destrucción del testamento ológrafo. El testamento ológrafo es revocado por su cancelación o destrucción hecha por el testador o por orden suya.", practicalEffects: ['En la práctica, este artículo rige cancelación o destrucción del testamento ológrafo. El testamento ológrafo es revocado por su cancelación o destrucción hecha por el testador o por orden suya.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cancelacin', 'destruccin', 'testamento', 'olgrafo', 'articulo 2515'], segments: [], amendments: [] },
  { id: 'ccyc-art-2516', lawId: 'codigo-civil-comercial', number: '2516', order: 2516, title: "Revocación del legado por transmisión, transformación o gravamen de la cosa", text: "Revocación del legado por transmisión, transformación o gravamen de la cosa. La transmisión de la cosa legada revoca el legado, aunque el acto no sea válido por defecto de forma o la cosa vuelva al dominio del testador. El mismo efecto produce la promesa bilateral de compraventa, aunque el acto sea simulado. La subasta dispuesta judicialmente y la expropiación implican revocación del legado, excepto que la cosa vuelva a ser propiedad del testador. La transformación de la cosa debida al hecho del testador importa revocación del legado. La constitución de gravámenes sobre la cosa legada no revoca el legado.", plainLanguageExplanation: "Establece el régimen de revocación del legado por transmisión, transformación o gravamen de la cosa. La transmisión de la cosa legada revoca el legado, aunque el acto no sea válido por defecto de forma o la cosa vuelva al dominio del testador.", practicalEffects: ['En la práctica, este artículo rige revocación del legado por transmisión, transformación o gravamen de la cosa. La transmisión de la cosa legada revoca el legado, aunque el acto no sea válido por defecto de forma o la cosa vuelva al dominio del testador.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['revocacin', 'legado', 'transmisin', 'transformacin', 'gravamen', 'cosa', 'articulo 2516'], segments: [], amendments: [] },
  { id: 'ccyc-art-2517', lawId: 'codigo-civil-comercial', number: '2517', order: 2517, title: "Responsabilidad de los herederos", text: "Responsabilidad de los herederos. Si la cosa legada se pierde o deteriora por el hecho o culpa de uno de los herederos, sólo responde del legado el heredero por cuya culpa o hecho se ha perdido o deteriorado.", plainLanguageExplanation: "Establece el régimen de responsabilidad de los herederos. Si la cosa legada se pierde o deteriora por el hecho o culpa de uno de los herederos, sólo responde del legado el heredero por cuya culpa o hecho se ha perdido o deteriorado.", practicalEffects: ['En la práctica, este artículo rige responsabilidad de los herederos. Si la cosa legada se pierde o deteriora por el hecho o culpa de uno de los herederos, sólo responde del legado el heredero por cuya culpa o hecho se h'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'herederos', 'articulo 2517'], segments: [], amendments: [] },
  { id: 'ccyc-art-2518', lawId: 'codigo-civil-comercial', number: '2518', order: 2518, title: "Caducidad de la institución por premoriencia", text: "Caducidad de la institución por premoriencia. La institución de heredero o legatario caduca cuando el instituido muere antes que el testador o antes del cumplimiento de la condición de la que depende la adquisición de la herencia o el legado.", plainLanguageExplanation: "Establece el régimen de caducidad de la institución por premoriencia. La institución de heredero o legatario caduca cuando el instituido muere antes que el testador o antes del cumplimiento de la condición de la que depende la adquisición de la herencia o el legado.", practicalEffects: ['En la práctica, este artículo rige caducidad de la institución por premoriencia. La institución de heredero o legatario caduca cuando el instituido muere antes que el testador o antes del cumplimiento de la condición de la que depe'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caducidad', 'institucin', 'premoriencia', 'articulo 2518'], segments: [], amendments: [] },
  { id: 'ccyc-art-2519', lawId: 'codigo-civil-comercial', number: '2519', order: 2519, title: "Caducidad del legado por perecimiento y por transformación de la cosa", text: "Caducidad del legado por perecimiento y por transformación de la cosa. El legado de cosa cierta y determinada caduca cuando ésta perece totalmente, por cualquier causa, antes de la apertura de la sucesión o del cumplimiento de la condición suspensiva a que estaba sometido; también cuando perece por caso fortuito, después de la apertura de la sucesión o del cumplimiento de la condición. Si la cosa legada perece parcialmente, el legado subsiste por la parte que se conserva. El legado caduca por la transformación de la cosa por causa ajena a la voluntad del testador, anterior a la muerte de éste o al cumplimiento de la condición suspensiva.", plainLanguageExplanation: "Establece el régimen de caducidad del legado por perecimiento y por transformación de la cosa. El legado de cosa cierta y determinada caduca cuando ésta perece totalmente, por cualquier causa, antes de la apertura de la sucesión o del cumplimiento de la condición suspensiva a que estaba sometido; también cuando perece por caso fortuito, después de la apertura de la sucesió", practicalEffects: ['En la práctica, este artículo rige caducidad del legado por perecimiento y por transformación de la cosa. El legado de cosa cierta y determinada caduca cuando ésta perece totalmente, por cualquier causa, antes de la apertura de la sucesión o del cumplimien'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caducidad', 'legado', 'perecimiento', 'transformacin', 'cosa', 'articulo 2519'], segments: [], amendments: [] },
  { id: 'ccyc-art-2520', lawId: 'codigo-civil-comercial', number: '2520', order: 2520, title: "Revocación del legado por causa imputable al legatario", text: "Revocación del legado por causa imputable al legatario. Los legados pueden ser revocados, a instancia de los interesados: a) por ingratitud del legatario que, después de haber entrado en el goce de los bienes legados, injuria gravemente la memoria del causante; b) por incumplimiento de los cargos impuestos por el testador si son la causa final de la disposición. En este caso, los herederos quedan obligados al cumplimiento de los cargos.", plainLanguageExplanation: "Establece el régimen de revocación del legado por causa imputable al legatario. Los legados pueden ser revocados, a instancia de los interesados: a) por ingratitud del legatario que, después de haber entrado en el goce de los bienes legados, injuria gravemente la memoria del causante; b) por incumplimiento de los cargos impuestos por el testador si son la ca", practicalEffects: ['En la práctica, este artículo rige revocación del legado por causa imputable al legatario. Los legados pueden ser revocados, a instancia de los interesados: a) por ingratitud del legatario que, después de haber entrado en el goce de los bien'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['revocacin', 'legado', 'causa', 'imputable', 'legatario', 'articulo 2520'], segments: [], amendments: [] },
  { id: 'ccyc-art-2521', lawId: 'codigo-civil-comercial', number: '2521', order: 2521, title: "Renuncia del legatario", text: "Renuncia del legatario. El legatario puede renunciar al legado en tanto no lo haya aceptado. Cualquier interesado puede pedir al juez la fijación de un plazo para que el instituido se pronuncie, bajo apercibimiento de tenerlo por renunciante.", plainLanguageExplanation: "Establece el régimen de renuncia del legatario. El legatario puede renunciar al legado en tanto no lo haya aceptado.", practicalEffects: ['En la práctica, este artículo rige renuncia del legatario. El legatario puede renunciar al legado en tanto no lo haya aceptado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['renuncia', 'legatario', 'articulo 2521'], segments: [], amendments: [] },
  { id: 'ccyc-art-2522', lawId: 'codigo-civil-comercial', number: '2522', order: 2522, title: "Renuncia parcial", text: "Renuncia parcial. Legado plural. La renuncia de un legado no puede ser parcial. Si se han hecho dos o más legados a una misma persona, uno de los cuales es con cargo, no puede renunciar a éste y aceptar los legados libres. CAPITULO 7 Albaceas", plainLanguageExplanation: "Establece el régimen de renuncia parcial. Legado plural.", practicalEffects: ['En la práctica, este artículo rige renuncia parcial. Legado plural.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['renuncia', 'parcial', 'articulo 2522'], segments: [], amendments: [] },
  { id: 'ccyc-art-2523', lawId: 'codigo-civil-comercial', number: '2523', order: 2523, title: "Atribuciones", text: "Atribuciones. Las atribuciones del albacea designado en el testamento son las conferidas por el testador y, en defecto de ello, las que según las circunstancias son necesarias para lograr el cumplimiento de su voluntad. El testador no puede dispensar al albacea de los deberes de inventariar los bienes y de rendir cuentas. Si el testador designa varios albaceas, el cargo es ejercido por cada uno de ellos en el orden en que están nombrados, excepto que el testador disponga el desempeño de todos conjuntamente. En tal caso, las decisiones deben ser tomadas por mayoría de albaceas y, faltando ésta, por el juez.", plainLanguageExplanation: "Establece el régimen de atribuciones. Las atribuciones del albacea designado en el testamento son las conferidas por el testador y, en defecto de ello, las que según las circunstancias son necesarias para lograr el cumplimiento de su voluntad.", practicalEffects: ['En la práctica, este artículo rige atribuciones. Las atribuciones del albacea designado en el testamento son las conferidas por el testador y, en defecto de ello, las que según las circunstancias son'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['atribucionesarticulo 2523'], segments: [], amendments: [] },
  { id: 'ccyc-art-2524', lawId: 'codigo-civil-comercial', number: '2524', order: 2524, title: "Forma de la designación", text: "Forma de la designación. Capacidad. El nombramiento del albacea debe ajustarse a las formas testamentarias, aunque no se realice en el testamento cuya ejecución se encomienda. Pueden ser albaceas las personas humanas plenamente capaces al momento en que deben desempeñar el cargo, las personas jurídicas, y los organismos de la administración pública centralizada o descentralizada. Cuando se nombra a un funcionario público, la designación se estima ligada a la función, cualquiera que sea la persona que la sirve.", plainLanguageExplanation: "Establece el régimen de forma de la designación. Capacidad.", practicalEffects: ['En la práctica, este artículo rige forma de la designación. Capacidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['forma', 'designacin', 'articulo 2524'], segments: [], amendments: [] },
  { id: 'ccyc-art-2525', lawId: 'codigo-civil-comercial', number: '2525', order: 2525, title: "Delegación", text: "Delegación. El albacea no puede delegar el encargo recibido, el que no se transmite a sus herederos. No está obligado a obrar personalmente; le es permitido hacerlo por mandatarios que actúen a su costa y por su cuenta y riesgo, aun cuando el testador haya designado albacea subsidiario. Si el albacea actúa con patrocinio letrado, los honorarios del abogado patrocinarte sólo deben ser sufragados por la sucesión si sus trabajos resultan necesarios o razonablemente convenientes para el cumplimiento del albaceazgo.", plainLanguageExplanation: "Establece el régimen de delegación. El albacea no puede delegar el encargo recibido, el que no se transmite a sus herederos.", practicalEffects: ['En la práctica, este artículo rige delegación. El albacea no puede delegar el encargo recibido, el que no se transmite a sus herederos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['delegacinarticulo 2525'], segments: [], amendments: [] },
  { id: 'ccyc-art-2526', lawId: 'codigo-civil-comercial', number: '2526', order: 2526, title: "Deberes y facultades del albacea", text: "Deberes y facultades del albacea. El albacea debe poner en seguridad el caudal hereditario y practicar el inventario de los bienes con citación de los interesados. Debe pagar los legados con conocimiento de los herederos y reservar los bienes de la herencia suficientes para proveer a las disposiciones del testador dándoles oportunamente el destino adecuado. Debe demandar a los herederos y legatarios por el cumplimiento de los cargos que el testador les haya impuesto. La oposición de los herederos o de alguno de ellos al pago de los legados, suspende su ejecución hasta la resolución de la controversia entre los herederos y los legatarios afectados. El albacea está obligado a rendir cuentas de su gestión a los herederos.", plainLanguageExplanation: "Establece el régimen de deberes y facultades del albacea. El albacea debe poner en seguridad el caudal hereditario y practicar el inventario de los bienes con citación de los interesados.", practicalEffects: ['En la práctica, este artículo rige deberes y facultades del albacea. El albacea debe poner en seguridad el caudal hereditario y practicar el inventario de los bienes con citación de los interesados.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['deberes', 'facultades', 'albacea', 'articulo 2526'], segments: [], amendments: [] },
  { id: 'ccyc-art-2527', lawId: 'codigo-civil-comercial', number: '2527', order: 2527, title: "Responsabilidad", text: "Responsabilidad. El albacea responde por los daños que el incumplimiento de sus deberes cause a herederos y legatarios.", plainLanguageExplanation: "Establece el régimen de responsabilidad. El albacea responde por los daños que el incumplimiento de sus deberes cause a herederos y legatarios.", practicalEffects: ['En la práctica, este artículo rige responsabilidad. El albacea responde por los daños que el incumplimiento de sus deberes cause a herederos y legatarios.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidadarticulo 2527'], segments: [], amendments: [] },
  { id: 'ccyc-art-2528', lawId: 'codigo-civil-comercial', number: '2528', order: 2528, title: "Facultades de herederos y legatarios", text: "Facultades de herederos y legatarios. Los herederos y los legatarios conservan las facultades cuyo desempeño no es atribuido por la ley o por el testador al albacea. Los herederos pueden solicitar la destitución del albacea por incapacidad sobreviniente, negligencia, insolvencia o mala conducta en el desempeño de la función, y en cualquier tiempo poner término a su cometido pagando las deudas y legados, o depositando los fondos necesarios a tal fin, o acordando al respecto con todos los interesados. Los herederos y legatarios pueden solicitar las garantías necesarias en caso de justo temor por la seguridad de los bienes que están en poder del albacea.", plainLanguageExplanation: "Establece el régimen de facultades de herederos y legatarios. Los herederos y los legatarios conservan las facultades cuyo desempeño no es atribuido por la ley o por el testador al albacea.", practicalEffects: ['En la práctica, este artículo rige facultades de herederos y legatarios. Los herederos y los legatarios conservan las facultades cuyo desempeño no es atribuido por la ley o por el testador al albacea.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['facultades', 'herederos', 'legatarios', 'articulo 2528'], segments: [], amendments: [] },
  { id: 'ccyc-art-2529', lawId: 'codigo-civil-comercial', number: '2529', order: 2529, title: "Supuesto de inexistencia de herederos", text: "Supuesto de inexistencia de herederos. Cuando no hay herederos o cuando los legados insumen la totalidad del haber sucesorio y no hay derecho a acrecer entre los legatarios, el albacea es el representante de la sucesión, debiendo hacer inventario judicial de los bienes recibidos e intervenir en todos los juicios en que la sucesión es parte. Le compete la administración de los bienes sucesorios conforme a lo establecido para el curador de la herencia vacante. Está facultado para proceder, con intervención del juez, a la transmisión de los bienes que sea indispensable para cumplir la voluntad del causante. Siempre que se cuestione la validez del testamento o el alcance de sus disposiciones, el albacea es parte en el juicio aun cuando haya herederos instituidos.", plainLanguageExplanation: "Establece el régimen de supuesto de inexistencia de herederos. Cuando no hay herederos o cuando los legados insumen la totalidad del haber sucesorio y no hay derecho a acrecer entre los legatarios, el albacea es el representante de la sucesión, debiendo hacer inventario judicial de los bienes recibidos e intervenir en todos los juicios en qu", practicalEffects: ['En la práctica, este artículo rige supuesto de inexistencia de herederos. Cuando no hay herederos o cuando los legados insumen la totalidad del haber sucesorio y no hay derecho a acrecer entre los legatarios, el albacea es e'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['supuesto', 'inexistencia', 'herederos', 'articulo 2529'], segments: [], amendments: [] },
  { id: 'ccyc-art-2530', lawId: 'codigo-civil-comercial', number: '2530', order: 2530, title: "Remuneración", text: "Remuneración. Gastos. El albacea debe percibir la remuneración fijada en el testamento o, en su defecto, la que el juez le asigna, conforme a la importancia de los bienes legados y a la naturaleza y eficacia de los trabajos realizados. Si el albacea es un legatario, se entiende que el desempeño de la función constituye un cargo del legado, sin que corresponda otra remuneración excepto que deba entenderse, según las circunstancias, que era otra la voluntad del testador. Deben reembolsarse al albacea los gastos en que incurra para llenar su cometido y pagársele por separado los honorarios o la remuneración que le corresponden por trabajos de utilidad para la sucesión que haya efectuado en ejercicio de una profesión.", plainLanguageExplanation: "Establece el régimen de remuneración. Gastos.", practicalEffects: ['En la práctica, este artículo rige remuneración. Gastos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remuneracinarticulo 2530'], segments: [], amendments: [] },
  { id: 'ccyc-art-2531', lawId: 'codigo-civil-comercial', number: '2531', order: 2531, title: "Conclusión", text: "Conclusión. El albaceazgo concluye por la ejecución completa del testamento, por el vencimiento del plazo fijado por el testador y por la muerte, incapacidad sobreviniente, renuncia o destitución del albacea. Cuando por cualquier causa cesa el albacea designado y subsiste la necesidad de llenar el cargo vacante, lo provee el juez con audiencia de los herederos y legatarios. LIBRO SEXTO DISPOSICIONES COMUNES A LOS DERECHOS PERSONALES Y REALES TITULO I Prescripción y caducidad CAPITULO 1 Disposiciones comunes a la prescripción liberatoria y adquisitiva SECCION 1ª Normas generales", plainLanguageExplanation: "Establece el régimen de conclusión. El albaceazgo concluye por la ejecución completa del testamento, por el vencimiento del plazo fijado por el testador y por la muerte, incapacidad sobreviniente, renuncia o destitución del albacea.", practicalEffects: ['En la práctica, este artículo rige conclusión. El albaceazgo concluye por la ejecución completa del testamento, por el vencimiento del plazo fijado por el testador y por la muerte, incapacidad sobreviniente, renuncia o destitución del albacea.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conclusinarticulo 2531'], segments: [], amendments: [] },
];
